var action:GUIDEAction:
	set(value):
		if is_instance_valid(action):
			action.changed.disconnect(_refresh)

		action = value

		if is_instance_valid(action):
			action.changed.connect(_refresh)

		# action_changed can only be emitted by 
		# dragging an action into this, not when setting
		# the property
		_refresh()


func _refresh():
