@tool
@icon("guide_virtual_button.svg")
## A virtual joystick button.
class_name GUIDEVirtualButton
extends GUIDEVirtualJoyBase

## Radius of the button.
@export var button_radius: float = 100:
	set(value):
		button_radius = value
		queue_redraw()
		configuration_changed.emit()

## The joy button represented by this virtual button.
@export var button_index: JoyButton = JOY_BUTTON_A:
	set(value):
		button_index = value
		configuration_changed.emit()

## The finger positions that are currently touching the screen.
var _finger_positions:Dictionary = {}

## Whether or not we consumed the mouse down event.
var _mouse_down_consumed: bool = false

func _ready() -> void:
	use_top_left = true
	mouse_filter = Control.MOUSE_FILTER_IGNORE
	size = Vector2.ZERO
	# the editor likes to set the size to 40x40, we'll override that
	if Engine.is_editor_hint():
		set_deferred("size", Vector2.ZERO)

	# let renderers know the initial configuration
	configuration_changed.emit()
	# and the initial state
	changed.emit()

	if Engine.is_editor_hint():
		return # no input processing in the editor

	_reconnect()
	_report_input()


## Handles input from the mouse.
func _handle_mouse_input(event:InputEventMouse) -> void:
	var pos := _screen_to_world(event.position)
	if not _is_actuated:
		if event is InputEventMouseMotion:
			if Input.is_mouse_button_pressed(MOUSE_BUTTON_LEFT):
				# try to actuate joystick at the given position
				# print("try_actuate", pos, event.position)
				_try_actuate(pos)
				if _is_over_button(pos):
					get_viewport().set_input_as_handled()
			return

		if event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
			# try to actuate button at the given position
			_try_actuate(pos)

			# we handled this input if it was over the button, otherwise let it propagate
			if _is_over_button(pos):
				_mouse_down_consumed = true
				get_viewport().set_input_as_handled()
		return

	# actuated
	# if the mouse leaves the button area while moving, release
	# this works differently than a UI button which would only release
	# on mouse up, but this is more like a physical button would behave.
	if event is InputEventMouseMotion:
		# check if the mouse is still over the button
		if not _is_over_button(pos):
			_release()
		get_viewport().set_input_as_handled()
		return

	# mouse button released, release the button
	if not event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
		_release()
		# only consume the event if we also consumed the press

		get_viewport().set_input_as_handled()


## Handles input from touch devices.
func _handle_touch_input(event:InputEvent) -> void:
	# update finger positions
	if event is InputEventScreenTouch:
		if event.pressed:
			_finger_positions[event.index] = event.position
		else:
			_finger_positions.erase(event.index)
	elif event is InputEventScreenDrag:
		_finger_positions[event.index] = event.position

	# everything that happens over the button area is considered handled
	if _is_over_button(event.position):
		get_viewport().set_input_as_handled()

	if not _is_actuated:
		# if any finger is over the button area, try to actuate
		for position:Vector2 in _finger_positions.values():
			var pos := _screen_to_world(position)
			_try_actuate(pos)
		return

	# actuated
	# if no finger is currently over the button area, release
	for position:Vector2 in _finger_positions.values():
		var pos := _screen_to_world(position)
		if _is_over_button(pos):
			return  # still over the button, do nothing

	_release()

## Returns whether the given world position is over the button area.
func _is_over_button(world_position:Vector2) -> bool:
	return global_position.distance_squared_to(world_position) <= button_radius * button_radius


## Tries to actuate the button using the given world position.
func _try_actuate(world_position: Vector2):
	if not _is_actuated and _is_over_button(world_position) :
		_is_actuated = true
		_report_input()

## Releases the button.
func _release():
	if _is_actuated:
		_is_actuated = false
		_report_input()

## Reports the current input state to the input system.
func _report_input():
	var event := InputEventJoypadButton.new()
	event.button_index = button_index
	event.pressed = _is_actuated
	event.device = _virtual_joy_id
	GUIDE.inject_input(event)
	if draw_debug:
		queue_redraw()
	changed.emit()

## Draws the debug representation of the button.
func _draw():
	if not draw_debug:
		return
	## 
	var color := Color(0.9, 0.9, 0.9, 0.8) if _is_actuated else Color(0.5, 0.5, 0.5, 0.5)
	draw_circle(Vector2.ZERO, button_radius, color)

@tool
@icon("guide_virtual_button_renderer.svg")
## Base class for virtual button renderers.
class_name GUIDEVirtualButtonRenderer
extends Control

var _button: GUIDEVirtualButton = null
var _was_actuated:bool = false

## Returns whether or not the button is currently actuated.
var is_button_actuated:bool:
	get:
		if _button != null:
			return _button._is_actuated
		return false		

## Returns the button radius.
var button_radius:float:
	get:
		if _button != null:
			return _button.button_radius
		return 0.0

func _notification(what:int) -> void:
	if what == NOTIFICATION_ENTER_TREE:

		_button = get_parent() as GUIDEVirtualButton
		if _button == null:
			push_error("Button renderer must be a child of GUIDEVirtualButton. Button renderer will not work.")
			return
		_button.configuration_changed.connect(_on_configuration_changed)
		if Engine.is_editor_hint():
			return
		# we only react to input changes in the real game, not in the editor.
		_button.changed.connect(func(): _update(_button._is_actuated))

## Called when configuration changed on the parent button.
func _on_configuration_changed() -> void:
	pass

## Function to be implemented by subclasses to update the button visuals.
## @param is_actuated: Whether or not the button is currently actuated.
func _update(is_actuated:bool) -> void:
	pass


func _get_configuration_warnings() -> PackedStringArray:
	var results: PackedStringArray = []

	if (get_parent() as GUIDEVirtualButton) == null:
		results.append("Button renderer must be a child of GUIDEVirtualButton")

	return results

@tool
@icon("guide_virtual_stick_renderer.svg")
## Base class for virtual stick renderers.
class_name GUIDEVirtualStickRenderer
extends Control


var _stick: GUIDEVirtualStick
var _was_actuated:bool = false

## Returns the stick radius from virtual stick.
var stick_radius: float:
	get:
		if _stick != null:
			return _stick.stick_radius
		return 0.0

## Returns the max actuation radius from the virtual stick.
var max_actuation_radius: float:
	get:
		if _stick != null:
			return _stick.max_actuation_radius
		return 0.0

## Returns the interaction zone radius from the virtual stick.
var interaction_zone_radius: float:
	get:
		if _stick != null:
			return _stick.interaction_zone_radius
		return 0.0

## Returns the position of the virtual stick relative to the center.	
var stick_position: Vector2:
	get:
		if _stick != null:
			return _stick.stick_relative_position
		return Vector2.ZERO

## Returns the starting position of the virtual stick in global coordinates.
var stick_start_position:Vector2:
	get:
		if _stick != null:
			return _stick._start_pos
		print("stick zero")
		return Vector2.ZERO


## Returns whether or not the stick is currently actuated.
var is_stick_actuated:bool:
	get:
		if _stick != null:
			return _stick._is_actuated
		return false		


func _notification(what:int) -> void:
	if what == NOTIFICATION_ENTER_TREE:
		_stick = get_parent() as GUIDEVirtualStick
		if _stick == null:
			push_error("Stick renderer must be a child of GUIDEVirtualStick. Stick renderer will not work.")
			return
		_stick.configuration_changed.connect(_on_configuration_changed)

		if Engine.is_editor_hint():
			return
		# we only react to input changes in the real game, not in the editor.
		_stick.changed.connect(_on_stick_changed)


## Called when configuration changed on the parent stick (e.g., radii or modes changed).
func _on_configuration_changed() -> void:
	pass


func _on_stick_changed() -> void:
	var direction: Vector2 = Vector2.ZERO
	# get the stick direction (if the stick is not in the start position)
	if not _stick._start_pos.is_equal_approx(_stick._current_pos):
		direction = _stick._start_pos.direction_to(_stick._current_pos)

	# get the distance from the start position to the current position to 
	# calculate the offset (normalized by the max actuation radius)
	var distance: float = _stick._start_pos.distance_to(_stick._current_pos)
	var offset: Vector2 = direction * (distance / _stick.max_actuation_radius)

	# track actuation state changes
	if _stick._is_actuated and not _was_actuated:
		_was_actuated = true

	if not _stick._is_actuated and _was_actuated:
		_was_actuated = false

	# Update the visuals based on the new state.
	_update(_stick._current_pos - global_position, offset, _stick._is_actuated)

## Function to be implemented by subclasses to update the stick visuals.
## @param joy_position The position relative to the position of this renderer.
## @param joy_offset The normalized joy offset from the center of the stick, 
## taking into account the max actuation radius.
func _update(joy_position: Vector2, joy_offset:Vector2, is_actuated:bool) -> void:
	pass



func _get_configuration_warnings() -> PackedStringArray:
	var results: PackedStringArray = []

	if (get_parent() as GUIDEVirtualStick) == null:
		results.append("Stick renderer must be a child of GUIDEVirtualStick")

	return results

