extends Container
## Used to load and hold the pages for the [RouterSlide] node.


#region Enums
## An Enum related to how this node will lazy-initiated [Page]s.
const PAGE_LOAD_MODE = RouterSlideInfo.PAGE_LOAD_MODE

## An Enum related to how this node will hide already initiated [Page]s that
## are outside of visible space.
const PAGE_HIDE_MODE = RouterSlideInfo.PAGE_HIDE_MODE
#endregion


#region External Variables
## All shared info about this router
@export var router_info : RouterSlideInfo:
	set(val):
		if router_info != val:
			if router_info:
				router_info.changed_hide_mode.disconnect(_on_hide_mode_changed)
				router_info.changed_load_mode.disconnect(_on_load_mode_changed)
				router_info.changed_size.disconnect(_on_size_changed)

				for info : RouterSlidePageInfo in router_info.page_infos:
					if info:
						info.changed_page_scene.disconnect(_on_page_changed)
						info.changed_page_idx.disconnect(_on_changed_page_idx)

			router_info = val
			if router_info:
				router_info.changed_hide_mode.connect(_on_hide_mode_changed)
				router_info.changed_load_mode.connect(_on_load_mode_changed)
				router_info.changed_size.connect(_on_size_changed)

				for info : RouterSlidePageInfo in router_info.page_infos:
					if info:
						info.changed_page_scene.connect(_on_page_changed)
						info.changed_page_idx.connect(_on_changed_page_idx)

			if is_node_ready():
				_on_info_update()

#endregion


#region Private Variables
var _pages : Array[Page]

var _page_reorder_queue : Array[int]
#endregion



#region Virtual Methods
func _notification(what: int) -> void:
	match what:
		NOTIFICATION_READY:
			_on_info_update()
		NOTIFICATION_SORT_CHILDREN:
			_on_sort_children()
#endregion


#region Private Methods (Info Update)
func _on_info_update() -> void:
	if !router_info:
		return

	_on_hide_mode_changed()
	_on_size_changed()
func _on_load_mode_changed() -> void:
	if router_info.page_load_mode == PAGE_LOAD_MODE.ALL:
		_bridge_call(0, router_info.size() - 1, _get_toggle_callable(true, PAGE_HIDE_MODE.HIDE_DISABLE))
		_bridge_call(0, router_info.size() - 1, _toggle_load.bind(true))
		return
	_refresh_offscreen_pages()
func _on_hide_mode_changed() -> void:
	_refresh_offscreen_pages()
func _on_size_changed() -> void:
	_pages.resize(router_info.size())
	queue_sort()
func _on_page_changed(page_idx : int) -> void:
	refresh_page(page_idx)
func _on_changed_page_idx(old_index : int, new_index : int) -> void:
	if _page_reorder_queue.is_empty():
		call_deferred("_page_idx_changed_queued")

	_page_reorder_queue.append(old_index)
	_page_reorder_queue.append(new_index)
#endregion


#region Private Methods (Helper)
func _on_sort_children() -> void:
	if !router_info:
		return
	for idx : int in _pages.size():
		var page := _pages[idx]
		if page:
			fit_child_in_rect(page, get_page_rect(idx))

func _page_idx_changed_queued() -> void:
	var old_pages : Array[Page] = _pages.duplicate()

	for i : int in range(_page_reorder_queue.size() >> 1):
		var from : int = _page_reorder_queue[i << 1]
		var to : int = _page_reorder_queue[(i << 1) + 1]

		var page : Page = old_pages[from]
		if page:
			fit_child_in_rect(page, get_page_rect(to))
		_pages[to] = page

	_page_reorder_queue.clear()
	_toggle_load(router_info.get_index(), true)
	_refresh_offscreen_pages()

func _refresh_offscreen_pages() -> void:
	var foo : Callable
	match router_info.page_hide_mode:
		PAGE_HIDE_MODE.NONE:
			foo = _multi_function.bind(_toggle_visible.bind(true), _toggle_processing.bind(true))
		PAGE_HIDE_MODE.HIDE:
			foo = _multi_function.bind(_toggle_visible.bind(false), _toggle_processing.bind(true))
		PAGE_HIDE_MODE.DISABLE:
			foo = _multi_function.bind(_toggle_visible.bind(true), _toggle_processing.bind(false))
		PAGE_HIDE_MODE.HIDE_DISABLE:
			foo = _multi_function.bind(_toggle_visible.bind(false), _toggle_processing.bind(false))
		PAGE_HIDE_MODE.UNLOAD:
			foo = _toggle_load.bind(false)

	_bridge_call(0, router_info.get_index() - 1, foo)
	_bridge_call(router_info.get_index() + 1, router_info.size() - 1, foo)
#endregion


#region Private Methods (Helper Multi-Function)
func _bridge_call(st : int, ed : int, foo : Callable) -> void:
	if _pages.is_empty():
		return

	for idx : int in range(st, ed + 1):
		foo.call(idx)

func _multi_function(idx : int, foo_1 : Callable, foo_2 : Callable) -> void:
	foo_1.call(idx)
	foo_2.call(idx)
#endregion


#region Private Methods (Rendering)
func _toggle_visible(idx : int, toggle : bool) -> void:
	if !router_info || !router_info.is_vaild_idx(idx) || !_pages[idx]:
		return
	_pages[idx].visible = toggle

func _toggle_processing(idx : int, toggle : bool) -> void:
	if !router_info || !router_info.is_vaild_idx(idx) || !_pages[idx]:
		return
	_pages[idx].process_mode = Node.PROCESS_MODE_INHERIT if toggle else Node.PROCESS_MODE_DISABLED

func _toggle_load(idx : int, toggle : bool) -> void:
	if !router_info || !router_info.is_vaild_idx(idx) || ((_pages[idx] != null) == toggle):
		return

	if toggle:
		# Load Page
		var page_scene := router_info.page_infos[idx].page
		if page_scene:
			var page : Page = page_scene.instantiate()
			_pages[idx] = page
			add_child(page)
			fit_child_in_rect(page, get_page_rect(idx))
		return

	if router_info.page_load_mode == PAGE_LOAD_MODE.ALL:
		return

	# Unload Page
	_pages[idx].queue_free()
	_pages[idx] = null
#endregion


#region Private Methods (Rendering Selector Utility)
func _get_toggle_callable(toggle : bool, hide_mode : PAGE_HIDE_MODE) -> Callable:
	match hide_mode:
		PAGE_HIDE_MODE.NONE:
			return func (idx : int): pass
		PAGE_HIDE_MODE.HIDE:
			return _toggle_visible.bind(toggle)
		PAGE_HIDE_MODE.DISABLE:
			return _toggle_processing.bind(toggle)
		PAGE_HIDE_MODE.HIDE_DISABLE:
			return _multi_function.bind(_toggle_visible.bind(toggle), _toggle_processing.bind(toggle))
		PAGE_HIDE_MODE.UNLOAD:
			return _toggle_load.bind(toggle)
	return Callable()
#endregion


#region Public Methods (Page)
## Gets the indexs of all currently visible page nodes.
func get_visible_pages() -> Array[int]:
	if !router_info:
		return [-1]

	var offset := -(position.x * router_info.size()) / size.x
	var flr := floori(offset)

	if is_equal_approx(offset, flr):
		return [flr]
	return [flr, flr + 1]

## Gets the page node associated with given page [param idx]. 
## [br][br]
## Returns [code]null[/code] if page is not loaded.
func get_page_node(idx : int) -> Page:
	if !router_info || !router_info.is_vaild_idx(idx) || !_pages[idx]:
		return null
	return _pages[idx]
#endregion


#region Public Methods (Animation)
## Adds the pages needed before animation.
## [br][br]
## Also see: [enum RouterSlideInfo.PAGE_HIDE_MODE].
func add_pages(from : int, to : int) -> void:
	if !router_info:
		return

	var foo := _get_toggle_callable(true, router_info.page_hide_mode)
	match router_info.page_load_mode:
		PAGE_LOAD_MODE.ON_DEMAND:
			_toggle_load(to, true)
			foo.call(to)
		PAGE_LOAD_MODE.ON_DEMAND_BRIDGE:
			# Swap if from > to
			if from > to:
				from = from ^ to
				to = from ^ to
				from = from ^ to

			_bridge_call(from, to, _toggle_load.bind(true))
			_bridge_call(from, to, foo)
		PAGE_LOAD_MODE.ALL:
			pass
## Removes the pages needed after animation.
## [br][br]
## Also see: [enum RouterSlideInfo.PAGE_HIDE_MODE].
func remove_pages(from : int, to : int) -> void:
	if !router_info:
		return

	var foo := _get_toggle_callable(false, router_info.page_hide_mode)
	match router_info.page_load_mode:
		PAGE_LOAD_MODE.ON_DEMAND:
			foo.call(from)
		PAGE_LOAD_MODE.ON_DEMAND_BRIDGE:
			# Swap if from > to
			if from > to:
				from = from ^ to
				to = from ^ to
				from = (from ^ to) + 1
			else:
				to -= 1

			_bridge_call(from, to, foo)
		PAGE_LOAD_MODE.ALL:
			pass
## Removes and adds only the pages needed, without animation.
func force_pages(from : int, to : int) -> void:
	if !router_info:
		return

	if router_info.page_load_mode != PAGE_LOAD_MODE.ALL:
		_get_toggle_callable(false, router_info.page_hide_mode).call(from)
		_toggle_load(to, true)
	_get_toggle_callable(true, router_info.page_hide_mode).call(to)

## Refreshes all pages. If a page isn't loaded, it does not reload it.
## Otherwise, unloads and reloads in.
func refresh_pages() -> void:
	for i : int in range(_pages.size()):
		refresh_page(i)
## Refreshes the given page. If the page isn't loaded, does nothing.
## Otherwise, unloads and reloads in.
func refresh_page(page_idx : int) -> void:
	if get_page_node(page_idx) == null:
		return
	_toggle_load(page_idx, false)
	_toggle_load(page_idx, true)
#endregion


#region Public Methods (Helper)
## Returns if the given [param idx] is vaild.
## [br][br]
## Also see [member page_infos].
func is_vaild_idx(idx : int) -> bool:
	return router_info && router_info.is_vaild_idx(idx)

## Returns the [Rect2] of a given page.
func get_page_rect(idx : int) -> Rect2:
	if !router_info:
		return Rect2()

	var page_width := size.x / router_info.size()
	return Rect2(
		Vector2(idx * page_width, 0),
		Vector2(page_width, size.y)
	)
#endregion

# Made by Xavier Alvarez. A part of the "FreeControl" Godot addon.
@tool
class_name RouterStack extends PanelContainer
## Handles a [Control] stack, between [Page] nodes, using [SwapContainer].

#region Signals
## Emits when the current [Page] requests an event.
signal event_action(event : StringName, args : Variant)

## Emits at the start of a transition.
signal start_transition
## Emits at the end of a transition.
signal end_transition
#endregion


#region Enums
## See [enum SwapContainer.ANIMATION_TYPE].
const ANIMATION_TYPE = SwapContainer.ANIMATION_TYPE
#endregion


#region External Variables
## The filepath to the [Page] node this to load on ready. If this path is invaild,
## or not to a [PackedScene] with a [Page] node root, nothing will be loaded on ready.
@export_file("*.tscn") var starting_page : String:
	set(val):
		if val != starting_page:
			starting_page = val
			if Engine.is_editor_hint() && is_node_ready():
				_clear_all_pages()
				if ResourceLoader.exists(starting_page) && starting_page.get_extension() == "tscn":
					route(starting_page, ANIMATION_TYPE.NONE, ANIMATION_TYPE.NONE)
## The max size of the stack. If the stack is too big, it will clear the oldest on
## the stack first.
@export_range(1, 1000, 1, "or_greater") var max_stack : int = 50:
	set(val):
		val = maxi(val, 1)
		if max_stack != val:
			max_stack = val


@export_group("Animation")
## Starts animation with the [Control] node outside of the visisble screen.
@export var from_outside_screen : bool:
	set(val):
		if val != from_outside_screen:
			from_outside_screen = val
			_stack.from_outside_screen = val
## Starts animation an offset of this amount of pixels (away from the center), start
## at the position the [Control] originally would be placed at.
@export_range(0, 500, 1, "or_less", "or_greater", "suffix:px") var offset : float:
	set(val):
		if val != offset:
			offset = val
			_stack.offset = val

@export_group("Easing")
## The [enum Tween.EaseType] that will be used as the new [Control] transitions in.
@export var ease_enter : Tween.EaseType = Tween.EaseType.EASE_IN_OUT:
	set(val):
		if val != ease_enter:
			ease_enter = val
			_stack.ease_enter = val
## The [enum Tween.EaseType] that will be used as the current [Control] transitions out.
@export var ease_exit : Tween.EaseType = Tween.EaseType.EASE_IN_OUT:
	set(val):
		if val != ease_exit:
			ease_exit = val
			_stack.ease_exit = val

@export_group("Transition")
## The [enum Tween.TransitionType] that will be used as the new [Control] transitions in.
@export var transition_enter : Tween.TransitionType = Tween.TransitionType.TRANS_CUBIC:
	set(val):
		if val != transition_enter:
			transition_enter = val
			_stack.transition_enter = val
## The [enum Tween.TransitionType] that will be used as the current [Control] transitions out.
@export var transition_exit : Tween.TransitionType = Tween.TransitionType.TRANS_CUBIC:
	set(val):
		if val != transition_exit:
			transition_exit = val
			_stack.transition_exit = val

@export_group("Duration")
## The duration of the animation used as the new [Control] transitions in.
@export_range(0.001, 5, 0.001, "or_greater", "suffix:sec") var duration_enter : float = 0.35:
	set(val):
		val = maxf(val, 0.001)
		if val != duration_enter:
			duration_enter = val
			_stack.duration_enter = val
## The duration of the animation used as the current [Control] transitions out.
@export_range(0.001, 5, 0.001, "or_greater", "suffix:sec") var duration_exit : float = 0.35:
	set(val):
		val = maxf(val, 0.001)
		if val != duration_exit:
			duration_exit = val
			_stack.duration_exit = val
#endregion


#region Private Variables
var _page_stack : Array[PageStackInfo] = []
var _params : Dictionary = {}
var _stack : SwapContainer
#endregion



#region Private Virtual Methods
func _init() -> void:
	if _stack && is_instance_valid(_stack):
		_stack.queue_free()
	_stack = SwapContainer.new()
	add_child(_stack)
	_stack.set_anchors_and_offsets_preset(Control.PRESET_FULL_RECT)

	_stack.start_transition.connect(start_transition.emit)
	_stack.end_transition.connect(end_transition.emit)

	_stack.from_outside_screen = from_outside_screen
	_stack.offset = offset

	_stack.ease_enter = ease_enter
	_stack.ease_exit = ease_exit

	_stack.transition_enter = transition_enter
	_stack.transition_exit = transition_exit

	_stack.duration_enter = duration_enter
	_stack.duration_exit = duration_exit

	_stack.mouse_filter = Control.MOUSE_FILTER_IGNORE

func _get_minimum_size() -> Vector2:
	if clip_contents:
		return Vector2.ZERO

	var min := Vector2.ZERO
	for child : Node in get_children():
		if child is Control && child.is_visible_in_tree():
			min = min.max(child.get_combined_minimum_size())
	return min
#endregion


#region Private Methods
func _handle_swap(
	enter_page : Page,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	front : bool = true
) -> void:
	var exit_page : Page = _stack.get_current()

	if enter_page:
		enter_page.entering.emit()
	if exit_page:
		exit_page.exiting.emit()

	await _stack.swap_control(
		enter_page,
		enter_animation,
		exit_animation,
		front
	)

	if enter_page:
		enter_page.entered.emit()
	if exit_page:
		exit_page.exited.emit()

func _append_to_page_queue(page_node: PageStackInfo) -> void:
	if !_page_stack.is_empty():
		_page_stack.back().get_page().event_action.disconnect(event_action.emit)
	if _page_stack.size() > max_stack:
		_page_stack.pop_front()
	_page_stack.append(page_node)

	var page := page_node.get_page()
	if page && !page.event_action.is_connected(event_action.emit):
		page.event_action.connect(event_action.emit)

func _reverse_animate(animation : ANIMATION_TYPE) -> ANIMATION_TYPE:
	match animation:
		ANIMATION_TYPE.NONE:
			return ANIMATION_TYPE.NONE
		ANIMATION_TYPE.LEFT:
			return ANIMATION_TYPE.RIGHT
		ANIMATION_TYPE.RIGHT:
			return ANIMATION_TYPE.LEFT
		ANIMATION_TYPE.TOP:
			return ANIMATION_TYPE.BOTTOM
		ANIMATION_TYPE.BOTTOM:
			return ANIMATION_TYPE.TOP
	return ANIMATION_TYPE.NONE


func _clear_stack() -> void:
	_page_stack = [_page_stack.back()]
func _clear_all_pages() -> void:
	_page_stack = []
#endregion


#region Public Methods
## Emits the [signal Page.entered] signal on the current [Page] displayed.
## [br][br]
## If this Router is a decedent of another [Page], connect that [Page]'s
## [signal Page.entered] with this method.
func emit_entered() -> void:
	var curr_page : Page = null if _page_stack.is_empty() else _page_stack[0].get_page()
	if curr_page:
		curr_page.entered.emit()
## Emits the [signal Page.entering] signal on the current [Page] displayed.
## [br][br]
## If this Router is a decedent of another [Page], connect that [Page]'s
## [signal Page.entering] with this method.
func emit_entering() -> void:
	var curr_page : Page = null if _page_stack.is_empty() else _page_stack[0].get_page()
	if curr_page:
		curr_page.entering.emit()
## Emits the [signal Page.exited] signal on the current [Page] displayed.
## [br][br]
## If this Router is a decedent of another [Page], connect that [Page]'s
## [signal Page.exited] with this method.
func emit_exited() -> void:
	var curr_page : Page = null if _page_stack.is_empty() else _page_stack[0].get_page()
	if curr_page:
		curr_page.exited.emit()
## Emits the [signal Page.exiting] signal on the current [Page] displayed.
## [br][br]
## If this Router is a decedent of another [Page], connect that [Page]'s
## [signal Page.exiting] with this method.
func emit_exiting() -> void:
	var curr_page : Page = null if _page_stack.is_empty() else _page_stack[0].get_page()
	if curr_page:
		curr_page.exiting.emit()


## Routes to a [Page] node given by a file path to a [PackedScene].
func route(
	page_path : String,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	var packed : PackedScene = await LocalResourceLoader.new(get_tree().process_frame, page_path).finished
	if packed == null:
		push_error("An error occured while attempting to load file at filepath '", page_path, "'")
		return null

	return await route_packed(
		packed,
		enter_animation,
		exit_animation,
		params,
		args
	)
## Routes to a [Page] node given by a [PackedScene].
func route_packed(
	page_scene : PackedScene,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	if page_scene == null:
		push_error("page_scene cannot be 'null'")
		return null

	return await route_node(
		page_scene.instantiate(),
		enter_animation,
		exit_animation,
		params,
		args
	)
## Routes to a given [Page] node.
func route_node(
	page : Page,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	_params = params

	var enter_page := PageStackInfo.create(
		page,
		enter_animation,
		exit_animation,
		args.get("auto_clean", true)
	)

	_stack.set_modifers(args)
	_append_to_page_queue(enter_page)

	await _handle_swap(
		enter_page.get_page(),
		enter_animation,
		exit_animation
	)

	return page


## Routes to a [Page] node given by a file path to a [PackedScene]. Clears stack.
func navigate(
	page_path : String,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	var packed : PackedScene = await LocalResourceLoader.new(get_tree().process_frame, page_path).finished
	if packed == null:
		push_error("An error occured while attempting to load file at filepath '", page_path, "'")
		return null

	return await navigate_packed(
		packed,
		enter_animation,
		exit_animation,
		params,
		args
	)
## Routes to a [Page] node given by a [PackedScene]. Clears stack.
func navigate_packed(
	page_scene : PackedScene,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	if page_scene == null:
		push_error("page_scene cannot be 'null'")
		return null

	return await navigate_node(
		page_scene.instantiate(),
		enter_animation,
		exit_animation,
		params,
		args
	)
## Routes to a given [Page] node. Clears stack.
func navigate_node(
	page : Page,
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> Page:
	_params = params

	var enter_info := PageStackInfo.create(
		page,
		enter_animation,
		exit_animation,
		args.get("auto_clean", true)
	)

	_stack.set_modifers(args)
	_append_to_page_queue(enter_info)

	await _handle_swap(
		enter_info.get_page(),
		enter_animation,
		exit_animation
	)
	_clear_stack()

	return page


## Routes to the previous [Control] on the stack. If the stack is empty, nothing will happen.
func back(
	enter_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	exit_animation: ANIMATION_TYPE = ANIMATION_TYPE.DEFAULT,
	params : Dictionary = {},
	args : Dictionary = {}
) -> void:
	if is_empty():
		return
	_params = params
	_stack.set_modifers(args)

	var exit_page : PageStackInfo = _page_stack.pop_back()
	var enter_page : PageStackInfo = _page_stack.back()

	enter_page.get_page().event_action.connect(event_action.emit)

	if enter_animation == ANIMATION_TYPE.DEFAULT:
		enter_animation = _reverse_animate(exit_page.get_exit_animation())
	if exit_animation == ANIMATION_TYPE.DEFAULT:
		exit_animation = _reverse_animate(exit_page.get_enter_animation())

	await _handle_swap(
		enter_page.get_page(),
		enter_animation,
		exit_animation,
		false
	)


## Gets the parameters of the last route. 
func get_params() -> Dictionary:
	return _params
## Gets the current stack size.
func stack_size() -> int:
	return _page_stack.size()
## Returns if the stack is empty.
func is_empty() -> bool:
	return _page_stack.size() <= 1
## Returns the current [Page] on display.
func get_current_page() -> PageStackInfo:
	return null if _page_stack.is_empty() else _page_stack.back()

## Returns the [SwapContainer] used by this node. Freeing the node may result in
## crashes.
func get_swap_container() -> SwapContainer:
	return _stack
#endregion


#region Subclasses
class LocalResourceLoader:
	signal finished(scene : PackedScene)

	var _resource_name : String

	func _init(check_signal : Signal, path : StringName) -> void:
		_resource_name = path

		if !ResourceLoader.exists(_resource_name):
			push_error("Error - Invaild Resource Loaded")
			check_signal.connect(_delay_failsave, CONNECT_ONE_SHOT)
			return

		check_signal.connect(_on_signal)
		ResourceLoader.load_threaded_request(
			_resource_name,
			"PackedScene"
		)

	func _on_signal() -> void:
		match ResourceLoader.load_threaded_get_status(_resource_name):
			ResourceLoader.THREAD_LOAD_INVALID_RESOURCE, ResourceLoader.THREAD_LOAD_FAILED:
				finished.emit(null)
			ResourceLoader.THREAD_LOAD_LOADED:
				finished.emit(ResourceLoader.load_threaded_get(_resource_name))
	func _delay_failsave() -> void:
		finished.emit(null)
#endregion

