extends State

class_name JumpState

var state_name : String = "Jump"

var play_char : CharacterBody3D

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

	if !play_char.can_wallrun: #meaning that the character was wallrunning before jumping
		walljump()
	else:
		jump()

func verifications() -> void:
	if play_char.floor_snap_length != 0.0:  play_char.floor_snap_length = 0.0
	if play_char.jump_cooldown < play_char.jump_cooldown_ref: play_char.jump_cooldown = play_char.jump_cooldown_ref
	if play_char.hit_ground_cooldown != play_char.hit_ground_cooldown_ref: play_char.hit_ground_cooldown = play_char.hit_ground_cooldown_ref

	play_char.tween_hitbox_height(play_char.base_hitbox_height)
	play_char.tween_model_height(play_char.base_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

	wall_check()

func applies(delta : float) -> void:
	if !play_char.is_on_floor(): 
		if play_char.jump_cooldown > 0.0: play_char.jump_cooldown -= delta
		if play_char.coyote_jump_cooldown > 0.0: play_char.coyote_jump_cooldown -= delta
		if play_char.walljump_lock_in_air_movement_time > 0.0: play_char.walljump_lock_in_air_movement_time -= delta
		if play_char.velocity.y < 0.0: transitioned.emit(self, "InairState")

	if play_char.is_on_floor():
		if play_char.move_direction: transitioned.emit(self, play_char.walk_or_run)
		else: transitioned.emit(self, "IdleState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		if play_char.jump_cooldown < 0.0:
			jump()

	if Input.is_action_just_pressed(play_char.dash_action):
		if play_char.time_bef_can_dash_again <= 0.0 and play_char.nb_dashs_allowed > 0:
			transitioned.emit(self, "DashState")

	if Input.is_action_just_pressed(play_char.fly_action):
		transitioned.emit(self, "FlyState")

func wall_check() -> void:
	#check if play char collide with a left or right wall, and if all the conditions are correct, start wallrunning (by transitioning to the wallrun state)
	if play_char.can_wallrun and (!play_char.is_on_floor() or play_char.is_on_wall()) and !play_char.wallrun_floor_check.is_colliding():
		if play_char.left_wall_check.is_colliding() and !play_char.right_wall_check.is_colliding() and \
		play_char.last_wallrunned_wall_out_of_time != -1: #if play char has wallrunned on this side 'till the end of his wallrun time, he can't just rewallrun directly to this side, he has to either change side, or change wallrun direction
			play_char.side_check_raycast_collided = -1
			play_char.last_wallrunned_wall_out_of_time = 0
			transitioned.emit(self, "WallrunState")
		elif !play_char.left_wall_check.is_colliding() and play_char.right_wall_check.is_colliding() and \
		play_char.last_wallrunned_wall_out_of_time != 1:
			play_char.side_check_raycast_collided = 1
			play_char.last_wallrunned_wall_out_of_time = 0
			transitioned.emit(self, "WallrunState")
		else:
			return

func move(delta : float) -> void:
	play_char.input_direction = Input.get_vector(play_char.move_left_action, play_char.move_right_action, play_char.move_forward_action, play_char.move_backward_action)
	play_char.move_direction = (play_char.cam_holder.global_basis * Vector3(play_char.input_direction.x, 0.0, play_char.input_direction.y)).normalized()

	play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

	if !play_char.is_on_floor():
		if play_char.move_direction:
			if play_char.desired_move_speed < play_char.max_desired_move_speed: play_char.desired_move_speed += play_char.bunny_hop_dms_incre * delta

			#use of curves here to have a better in air movement
			var contrd_des_move_speed : float = play_char.desired_move_speed_curve.sample(play_char.desired_move_speed)
			var contrd_inair_move_speed : float = play_char.in_air_move_speed_curve.sample(play_char.desired_move_speed) * 1.0

			if play_char.walljump_lock_in_air_movement_time <= 0.0: #lock the in air movement for a bit when walljumping, to not having the in air velocity decided by input crush the velocity of the walljump
				play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * contrd_des_move_speed, contrd_inair_move_speed * delta)
				play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * contrd_des_move_speed, contrd_inair_move_speed * delta)

			var horizontal_velocity = Vector3(play_char.velocity.x, 0.0, play_char.velocity.z)
			if horizontal_velocity.length() > play_char.max_desired_move_speed:
				horizontal_velocity = horizontal_velocity.normalized() * play_char.max_desired_move_speed
				play_char.velocity.x = horizontal_velocity.x
				play_char.velocity.z = horizontal_velocity.z
		else:
			#accumulate desired speed for bunny hopping
			play_char.desired_move_speed = play_char.velocity.length()

func jump() -> void: 
	#manage the jump behaviour, depending of the different variables and states the character is

	var can_jump : bool = false #jump condition

	var jump_force_additions : float = 0.0 #accumulation of different buff values to apply to the y velocity once the play char jump

	#in air jump
	if !play_char.is_on_floor():
		if !play_char.coyote_jump_on and play_char.nb_jumps_in_air_allowed > 0:
			play_char.nb_jumps_in_air_allowed -= 1
			play_char.jump_cooldown = play_char.jump_cooldown_ref
			can_jump = true 

		if play_char.coyote_jump_on:
			play_char.jump_cooldown = play_char.jump_cooldown_ref
			play_char.coyote_jump_cooldown = -1.0 #so that the character cannot immediately make another coyote jump
			play_char.coyote_jump_on = false
			can_jump = true 

	#on floor jump
	if play_char.is_on_floor():
		play_char.jump_cooldown = play_char.jump_cooldown_ref
		can_jump = true 

	#jump buffering
	if play_char.buffered_jump:
		play_char.buffered_jump = false
		play_char.jump_cooldown = play_char.jump_cooldown_ref
		jump_force_additions += 0.0

	#apply jump
	if can_jump:
		play_char.velocity.y = play_char.jump_velocity + jump_force_additions
		can_jump = false

func walljump() -> void:
	var wall_normal = play_char.wall_normal

	var horizontal_velocity := Vector3(play_char.velocity.x,0.0,play_char.velocity.z)

	#remove the speed directed toward the wall
	var into_wall_velocity := horizontal_velocity.dot(wall_normal)
	if into_wall_velocity < 0.0: horizontal_velocity -= wall_normal * into_wall_velocity

	#add an impulse to exit the wall
	horizontal_velocity += wall_normal * play_char.walljump_push_force

	#applies the calculated wall jump speed
	play_char.velocity.x = horizontal_velocity.x
	play_char.velocity.z = horizontal_velocity.z
	play_char.velocity.y = play_char.walljump_y_velocity

	play_char.walljump_lock_in_air_movement_time = play_char.walljump_lock_in_air_movement_time_ref

extends State

class_name RunState

var state_name : String = "Run"

var play_char : CharacterBody3D

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

func verifications() -> void:
	play_char.move_speed = play_char.run_speed
	play_char.move_accel = play_char.run_accel
	play_char.move_deccel = play_char.run_deccel

	if play_char.floor_snap_length != 1.0: play_char.floor_snap_length = 1.0
	if play_char.jump_cooldown > 0.0: play_char.jump_cooldown = -1.0
	if play_char.nb_jumps_in_air_allowed < play_char.nb_jumps_in_air_allowed_ref: play_char.nb_jumps_in_air_allowed = play_char.nb_jumps_in_air_allowed_ref
	if play_char.coyote_jump_cooldown < play_char.coyote_jump_cooldown_ref: play_char.coyote_jump_cooldown = play_char.coyote_jump_cooldown_ref
	if play_char.has_dashed: play_char.has_dashed = false
	if play_char.last_wallrunned_wall_out_of_time != 0: play_char.last_wallrunned_wall_out_of_time = 0

	play_char.tween_hitbox_height(play_char.base_hitbox_height)
	play_char.tween_model_height(play_char.base_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

func applies(delta : float) -> void:
	if play_char.hit_ground_cooldown > 0.0: play_char.hit_ground_cooldown -= delta

	if !play_char.is_on_floor():
		if play_char.velocity.y < 0.0:
			transitioned.emit(self, "InairState")

	if play_char.is_on_floor():
		if play_char.auto_bunny_hop and play_char.hit_ground_cooldown > 0.0 and play_char.input_direction != Vector2.ZERO and play_char.jump_cooldown < 0.0:
			transitioned.emit(self, "JumpState")
		if play_char.jump_buff_on and play_char.jump_cooldown < 0.0:
			play_char.buffered_jump = true
			play_char.jump_buff_on = false
			transitioned.emit(self, "JumpState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		if play_char.jump_cooldown < 0.0:
			transitioned.emit(self, "JumpState")

	if Input.is_action_just_pressed(play_char.crouch_action) and !play_char.priority_over_crouch:
		transitioned.emit(self, "CrouchState")

	if play_char.continious_run:
		#has to press run button once to run
		if Input.is_action_just_pressed(play_char.run_action):
			play_char.walk_or_run = "WalkState"
			transitioned.emit(self, "WalkState")
	else:
		#has to continuously press run button to run
		if !Input.is_action_pressed(play_char.run_action):
			play_char.walk_or_run = "WalkState"
			transitioned.emit(self, "WalkState")

	if Input.is_action_just_pressed(play_char.slide_action):
		if play_char.time_bef_can_slide_again <= 0.0:
			transitioned.emit(self, "SlideState")

	if Input.is_action_just_pressed(play_char.dash_action):
		if play_char.time_bef_can_dash_again <= 0.0 and play_char.nb_dashs_allowed > 0:
			transitioned.emit(self, "DashState")

	if Input.is_action_just_pressed(play_char.fly_action):
		transitioned.emit(self, "FlyState")

func move(delta : float) -> void:
	play_char.input_direction = Input.get_vector(play_char.move_left_action, play_char.move_right_action, play_char.move_forward_action, play_char.move_backward_action)
	play_char.move_direction = (play_char.cam_holder.global_basis * Vector3(play_char.input_direction.x, 0.0, play_char.input_direction.y)).normalized()

	play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

	if play_char.move_direction and play_char.is_on_floor():
		play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * play_char.move_speed, play_char.move_accel * delta)
		play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * play_char.move_speed, play_char.move_accel * delta)

		if play_char.hit_ground_cooldown <= 0: play_char.desired_move_speed = play_char.velocity.length()
	else:
		transitioned.emit(self, "IdleState")

extends State

class_name SlideState

var state_name : String = "Slide"

var play_char : CharacterBody3D

var slope_angle : float

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

func verifications() -> void:
	play_char.move_speed = play_char.slide_speed
	play_char.move_accel = play_char.slide_accel
	play_char.move_deccel = 0.0

	play_char.slide_direction = play_char.move_direction.normalized() #get move direction before actually start sliding, and stick to that direction

	if play_char.floor_snap_length != 1.0: play_char.floor_snap_length = 1.0
	if play_char.jump_cooldown > 0.0: play_char.jump_cooldown = -1.0
	if play_char.nb_jumps_in_air_allowed < play_char.nb_jumps_in_air_allowed_ref: play_char.nb_jumps_in_air_allowed = play_char.nb_jumps_in_air_allowed_ref
	if play_char.coyote_jump_cooldown < play_char.coyote_jump_cooldown_ref: play_char.coyote_jump_cooldown = play_char.coyote_jump_cooldown_ref
	if play_char.has_dashed: play_char.has_dashed = false
	if play_char.last_wallrunned_wall_out_of_time != 0: play_char.last_wallrunned_wall_out_of_time = 0

	play_char.tween_hitbox_height(play_char.slide_hitbox_height)
	play_char.tween_model_height(play_char.slide_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

func applies(delta : float) -> void:
	if (play_char.global_position.y - play_char.last_frame_position.y) > play_char.uphill_tolerance: #check if play char is uphill
		play_char.slide_time = -1.0
		play_char.slide_direction = Vector3.ZERO
		if !raycast_verification():
			transitioned.emit(self, play_char.walk_or_run)
		else:
			transitioned.emit(self, "CrouchState")

	#if play_char.hitGroundCooldown > 0.0: play_char.hitGroundCooldown -= delta
	slope_angle = rad_to_deg(acos(play_char.get_floor_normal().dot(Vector3.UP)))

	#if current slope angle superior than max slope angle, play char slides indefinitely while he's on the slope
	if slope_angle < play_char.max_slope_angle:
		if play_char.slide_time > 0.0:
			if play_char.is_on_floor():
				play_char.slide_time -= delta
		else:
			play_char.slide_direction = Vector3.ZERO
			play_char.time_bef_can_slide_again = play_char.time_bef_can_slide_again_ref
			if !raycast_verification():
				transitioned.emit(self, play_char.walk_or_run)
			else:
				transitioned.emit(self, "CrouchState")

	if play_char.is_on_floor():
		if play_char.jump_buff_on and play_char.jump_cooldown < 0.0:
			play_char.buffered_jump = true
			play_char.jump_buff_on = false
			transitioned.emit(self, "JumpState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		#if nothing block play char when he will leave the slide state
		if (slope_angle > play_char.max_slope_angle or !raycast_verification()) and play_char.jump_cooldown < 0.0:
			#force break slide state
			play_char.slide_time = -1.0
			play_char.slide_direction = Vector3.ZERO
			play_char.time_bef_can_slide_again = play_char.time_bef_can_slide_again_ref
			transitioned.emit(self, "JumpState")

	if play_char.continious_slide: 
		#has to press slide button once to run
		if Input.is_action_just_pressed(play_char.slide_action):
			play_char.slide_time = -1.0
			play_char.slide_direction = Vector3.ZERO
			play_char.time_bef_can_slide_again = play_char.time_bef_can_slide_again_ref
			if !raycast_verification():
				transitioned.emit(self, play_char.walk_or_run)
			else:
				transitioned.emit(self, "CrouchState")
	else:
		#has to continuously press slide button to play_charouch
		if !Input.is_action_pressed(play_char.slide_action):
			if !raycast_verification():
				play_char.slide_time = -1.0
				play_char.slide_direction = Vector3.ZERO
				play_char.time_bef_can_slide_again = play_char.time_bef_can_slide_again_ref
				if !raycast_verification():
					transitioned.emit(self, play_char.walk_or_run)
				else:
					transitioned.emit(self, "CrouchState")

func raycast_verification() -> bool:
	#check if the raycast used to check ceilings is colliding or not
	return play_char.ceiling_check.is_colliding()

func move(delta : float) -> void:
	#can't change direction while sliding
	if play_char.slide_direction and play_char.is_on_floor():
		if play_char.desired_move_speed:
			play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

			#(play_char.desired_move_speed - play_char.amount_velocity_lost_per_sec * delta > 0.0) to avoid having negative move speed, and so slide in opposite direction than initial
			if slope_angle < play_char.max_slope_angle and (play_char.desired_move_speed - play_char.amount_velocity_lost_per_sec * delta > 0.0) : play_char.desired_move_speed -= play_char.amount_velocity_lost_per_sec * delta
			else: play_char.desired_move_speed += play_char.slope_sliding_dms_incre * delta

			play_char.velocity.x = play_char.move_direction.x * play_char.desired_move_speed
			play_char.velocity.z = play_char.move_direction.z * play_char.desired_move_speed
		else:
			if slope_angle < play_char.max_slope_angle and (play_char.desired_move_speed - play_char.amount_velocity_lost_per_sec * delta > 0.0): play_char.move_speed -= play_char.amount_velocity_lost_per_sec * delta
			else: play_char.move_speed += play_char.slope_sliding_ms_incre	 * delta

			play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * play_char.move_speed, play_char.move_accel * delta)
			play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * play_char.move_speed, play_char.move_accel * delta)

extends Node

@export var initial_state : State

var curr_state : State
var curr_state_name  : String
var states : Dictionary = {}

@onready var play_char : CharacterBody3D = $".."

signal change_fov

func _ready() -> void:
	#get all the state childrens
	for child in get_children():
		if child is State:
			states[child.name.to_lower()] = child
			child.transitioned.connect(on_state_child_transition)

	#if initial state, transition to it
	if initial_state:
		initial_state.enter(play_char)
		curr_state = initial_state
		curr_state_name = curr_state.state_name

func _process(delta : float) -> void:
	if curr_state: curr_state.update(delta)

func _physics_process(delta: float) -> void:
	if curr_state: curr_state.physics_update(delta)

func on_state_child_transition(state : State, new_state_name : String) -> void:
	#manage the transition from one state to another

	if state != curr_state: return

	var new_state = states.get(new_state_name.to_lower())
	if !new_state: return

	#exit the current state
	if curr_state: curr_state.exit()

	#enter the new state
	new_state.enter(play_char)

	curr_state = new_state
	curr_state_name = curr_state.state_name

	emit_signal("change_fov")

extends State

class_name CrouchState

var state_name : String = "Crouch"

var play_char : CharacterBody3D

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

func verifications() -> void:
	play_char.move_speed = play_char.crouch_speed
	play_char.move_deccel = play_char.crouch_accel
	play_char.move_deccel = play_char.crouch_deccel

	play_char.floor_snap_length = 1.0
	if play_char.jump_cooldown > 0.0: play_char.jump_cooldown = -1.0
	if play_char.nb_jumps_in_air_allowed < play_char.nb_jumps_in_air_allowed_ref: play_char.nb_jumps_in_air_allowed = play_char.nb_jumps_in_air_allowed_ref
	if play_char.coyote_jump_cooldown < play_char.coyote_jump_cooldown_ref: play_char.coyote_jump_cooldown = play_char.coyote_jump_cooldown_ref
	if play_char.has_dashed: play_char.has_dashed = false
	if play_char.last_wallrunned_wall_out_of_time != 0: play_char.last_wallrunned_wall_out_of_time = 0

	play_char.tween_hitbox_height(play_char.crouch_hitbox_height)
	play_char.tween_model_height(play_char.crouch_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

func applies(delta : float) -> void:
	if play_char.hit_ground_cooldown > 0.0: play_char.hit_ground_cooldown -= delta

	if !play_char.is_on_floor() and !play_char.is_on_wall():
		if play_char.velocity.y < 0.0:
			transitioned.emit(self, "InairState")

	if play_char.is_on_floor():
		if play_char.jump_buff_on and play_char.jump_cooldown < 0.0:
			play_char.buffered_jump = true
			play_char.jump_buff_on = false
			transitioned.emit(self, "JumpState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		if play_char.jump_cooldown < 0.0 and !raycast_verification(): #if nothing block the player character when it will leaves the play_charouch state
			transitioned.emit(self, "JumpState")

	if play_char.continious_crouch: 
		#has to press run button once to run
		if Input.is_action_just_pressed(play_char.crouch_action):
			if !raycast_verification():
				play_char.walk_or_run = "WalkState"
				transitioned.emit(self, "WalkState")
	else:
		#has to continuously press play_charouch button to play_charouch
		if !Input.is_action_pressed(play_char.crouch_action):
			if !raycast_verification():
				play_char.walk_or_run = "WalkState"
				transitioned.emit(self, "WalkState")

func raycast_verification() -> bool:
	#check if the raycast used to check ceilings is colliding or not
	return play_char.ceiling_check.is_colliding()

func move(delta : float) -> void:
	play_char.input_direction = Input.get_vector(play_char.move_left_action, play_char.move_right_action, play_char.move_forward_action, play_char.move_backward_action)
	play_char.move_direction = (play_char.cam_holder.global_basis * Vector3(play_char.input_direction.x, 0.0, play_char.input_direction.y)).normalized()

	play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

	if play_char.move_direction and play_char.is_on_floor():
		play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * play_char.move_speed, play_char.move_deccel * delta)
		play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * play_char.move_speed, play_char.move_deccel * delta)
	else:
		play_char.velocity.x = lerp(play_char.velocity.x, 0.0, play_char.move_deccel * delta)
		play_char.velocity.z = lerp(play_char.velocity.z, 0.0, play_char.move_deccel * delta)

	if play_char.hit_ground_cooldown <= 0: play_char.desired_move_speed = play_char.velocity.length()

extends State

class_name WalkState

var state_name : String = "Walk"

var play_char : CharacterBody3D

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

func verifications() -> void:
	play_char.move_speed = play_char.walk_speed
	play_char.move_accel = play_char.walk_accel
	play_char.move_deccel = play_char.walk_deccel

	play_char.floor_snap_length = 1.0
	if play_char.jump_cooldown > 0.0: play_char.jump_cooldown = -1.0
	if play_char.nb_jumps_in_air_allowed < play_char.nb_jumps_in_air_allowed_ref: play_char.nb_jumps_in_air_allowed = play_char.nb_jumps_in_air_allowed_ref
	if play_char.coyote_jump_cooldown < play_char.coyote_jump_cooldown_ref: play_char.coyote_jump_cooldown = play_char.coyote_jump_cooldown_ref
	if play_char.has_dashed: play_char.has_dashed = false
	if play_char.last_wallrunned_wall_out_of_time != 0: play_char.last_wallrunned_wall_out_of_time = 0

	play_char.tween_hitbox_height(play_char.base_hitbox_height)
	play_char.tween_model_height(play_char.base_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

func applies(delta : float) -> void:
	if play_char.hit_ground_cooldown > 0.0: play_char.hit_ground_cooldown -= delta

	if !play_char.is_on_floor() and !play_char.is_on_wall():
		if play_char.velocity.y < 0.0:
			transitioned.emit(self, "InairState")

	if play_char.is_on_floor():
		#check if can auto bunny hop
		if play_char.auto_bunny_hop and play_char.hit_ground_cooldown > 0.0 and play_char.input_direction != Vector2.ZERO and play_char.jump_cooldown < 0.0:
			transitioned.emit(self, "JumpState")
		if play_char.jump_buff_on and play_char.jump_cooldown < 0.0:
			#apply jump buffering
			play_char.buffered_jump = true
			play_char.jump_buff_on = false
			transitioned.emit(self, "JumpState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		if play_char.jump_cooldown < 0.0:
			transitioned.emit(self, "JumpState")

	if Input.is_action_just_pressed(play_char.crouch_action):
		transitioned.emit(self, "CrouchState")

	if Input.is_action_just_pressed(play_char.run_action):
		play_char.walk_or_run = "RunState"
		transitioned.emit(self, "RunState")

	if Input.is_action_just_pressed(play_char.dash_action):
		if play_char.time_bef_can_dash_again <= 0.0 and play_char.nb_dashs_allowed > 0:
			transitioned.emit(self, "DashState")

	if Input.is_action_just_pressed(play_char.fly_action):
		transitioned.emit(self, "FlyState")

func move(delta : float) -> void:
	play_char.input_direction = Input.get_vector(play_char.move_left_action, play_char.move_right_action, play_char.move_forward_action, play_char.move_backward_action)
	play_char.move_direction = (play_char.cam_holder.global_basis * Vector3(play_char.input_direction.x, 0.0, play_char.input_direction.y)).normalized()

	play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

	if play_char.move_direction and play_char.is_on_floor():
		#apply smooth move
		play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * play_char.move_speed, play_char.move_accel * delta)
		play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * play_char.move_speed, play_char.move_accel * delta)

		if play_char.hit_ground_cooldown <= 0: play_char.desired_move_speed = play_char.velocity.length()

	else:
		transitioned.emit(self, "IdleState")

extends CharacterBody3D

