run_action, crouch_action, jump_action, slide_action, dash_action, fly_action]
@export var check_on_ready_if_inputs_registered : bool = false

#references variables
@onready var cam_holder: Node3D = $CameraHolder
@onready var cam: Camera3D = %Camera
@onready var model: MeshInstance3D = $Model
@onready var hitbox: CollisionShape3D = $Hitbox
@onready var state_machine: Node = $StateMachine
@onready var hud: CanvasLayer = $HUD
@onready var ceiling_check: RayCast3D = %CeilingCheck
@onready var floor_check: RayCast3D = %FloorCheck
@onready var wallrun_floor_check : RayCast3D = %WallrunFloorCheck
@onready var slide_floor_check: RayCast3D = %SlideFloorCheck
@onready var left_wall_check : RayCast3D = %LeftWallCheck
@onready var right_wall_check : RayCast3D = %RightWallCheck

func _ready() -> void:
	#set and value references
	hit_ground_cooldown_ref = hit_ground_cooldown
	jump_cooldown_ref = jump_cooldown
	jump_cooldown = -1.0
	nb_jumps_in_air_allowed_ref = nb_jumps_in_air_allowed
	coyote_jump_cooldown_ref = coyote_jump_cooldown
	slide_time_ref = slide_time
	time_bef_can_slide_again_ref = time_bef_can_slide_again
	time_bef_can_slide_again = -1.0
	time_bef_can_dash_again_ref = time_bef_can_dash_again
	time_bef_can_dash_again = -1.0
	time_bef_reload_dash_ref = time_bef_reload_dash
	time_bef_reload_dash = -1.0
	nb_dashs_allowed_ref = nb_dashs_allowed
	wallrun_time_ref = wallrun_time
	time_bef_can_wallrun_again_ref = time_bef_can_wallrun_again
	walljump_lock_in_air_movement_time_ref = walljump_lock_in_air_movement_time
	walljump_lock_in_air_movement_time = -1.0

	input_actions_check()

func input_actions_check() -> void:
	#check if the input actions written in the editor are the same as the ones registered in the Input map, and if they are written correctly
	#if not, stop the program with an assert
	if check_on_ready_if_inputs_registered:
		var registered_input_actions: Array[StringName] = []
		for input_action in InputMap.get_actions():
			if input_action.begins_with(&"play_char_"):
				registered_input_actions.append(input_action)

		for input_action in input_actions_list:
			if input_action == &"":
				assert(false, "There's an undefined input action")

			if not registered_input_actions.has(input_action):
				assert(false, "%s missing in InputMap, or input action wrongly named in the editor" % input_action)

func _process(delta: float) -> void:
	wallrun_timer(delta)

	slide_timer(delta)

	dash_timer(delta)

func _physics_process(_delta: float) -> void:
	modify_physics_properties()

	move_and_slide()

func wallrun_timer(delta : float) -> void:
	if !can_wallrun:
		if time_bef_can_wallrun_again > 0.0: time_bef_can_wallrun_again -= delta
		else:
			#can only reset capacity of wallrunning when not currently wallrunning
			if state_machine.curr_state_name != "Wallrun":
				wallrun_time = wallrun_time_ref
				can_wallrun = true

func slide_timer(delta: float) -> void:
	if time_bef_can_slide_again > 0.0: time_bef_can_slide_again -= delta
	else:
		#can only reset slide time when not sliding
		if state_machine.curr_state_name != "Slide":
			slide_time = slide_time_ref

func dash_timer(delta: float) -> void:
	#reloads dash every *timeBefReloadDash* time, to avoid dash spamming
	#if you want to be able to spam dashes, set timeBefReloadDash to 0.0
	if nb_dashs_allowed < nb_dashs_allowed_ref:
		if time_bef_reload_dash > 0.0: time_bef_reload_dash -= delta
		else:
			time_bef_reload_dash = time_bef_reload_dash_ref
			nb_dashs_allowed += 1

	if time_bef_can_dash_again > 0.0: time_bef_can_dash_again -= delta
	else:
		#can only reset slide time when not dashing
		if state_machine.curr_state_name != "Dash":
			dash_time = dash_time_ref

func modify_physics_properties() -> void:
	last_frame_position = global_position #get play char global position every frame
	last_frame_velocity = velocity #get play char velocity every frame
	was_on_floor = !is_on_floor() #check if play char was on floor every frame

func gravity_apply(delta: float) -> void:
	# if play char goes up, apply jump gravity
	#otherwise, apply fall gravity
	if not is_on_floor(): #no need to push play char if he's already on the floor
		if velocity.y >= 0.0: velocity.y += jump_gravity * delta
		elif velocity.y < 0.0: velocity.y += fall_gravity * delta

#use of 2 tweens to change the hitbox and model heights, relative to a specific state
func tween_hitbox_height(state_hitbox_height : float) -> void:
	var hitbox_tween: Tween = create_tween()
	if hitbox != null:
		hitbox_tween.tween_method(func(v): set_hitbox_height(v), hitbox.shape.height, 
		state_hitbox_height, height_change_duration)
	#to avoid "no tweeners" error
	else:
		hitbox_tween.tween_interval(0.1)
	hitbox_tween.finished.connect(Callable(hitbox_tween, "kill"))

func set_hitbox_height(value: float) -> void:
	if hitbox.shape is CapsuleShape3D:
		hitbox.shape.height = value

func tween_model_height(state_model_height : float) -> void:
	var model_tween: Tween = create_tween()
	if model != null:
		model_tween.tween_property(model, "scale:y", 
		state_model_height, height_change_duration)
	#to avoid "no tweeners" error
	else:
		model_tween.tween_interval(0.1)
	model_tween.finished.connect(Callable(model_tween, "kill"))

extends State

class_name InairState

var state_name : String = "Inair"

var play_char : CharacterBody3D

func enter(play_char_ref : CharacterBody3D) -> void:
	play_char = play_char_ref

	verifications()

func verifications() -> void:
	if play_char.floor_snap_length != 0.0:  play_char.floor_snap_length = 0.0
	if play_char.hit_ground_cooldown != play_char.hit_ground_cooldown_ref: play_char.hit_ground_cooldown = play_char.hit_ground_cooldown_ref

	play_char.tween_hitbox_height(play_char.base_hitbox_height)
	play_char.tween_model_height(play_char.base_model_height)

func physics_update(delta : float) -> void:
	applies(delta)

	play_char.gravity_apply(delta)

	input_management()

	move(delta)

	wall_check()

func applies(delta : float) -> void:
	if !play_char.is_on_floor(): 
		if play_char.jump_cooldown > 0.0: play_char.jump_cooldown -= delta
		if play_char.coyote_jump_cooldown > 0.0: play_char.coyote_jump_cooldown -= delta
		if play_char.walljump_lock_in_air_movement_time > 0.0: play_char.walljump_lock_in_air_movement_time -= delta

	if play_char.is_on_floor():
		if play_char.jump_buff_on: 
			play_char.buffered_jump = true
			play_char.jump_buff_on = false
			transitioned.emit(self, "JumpState")
		if play_char.slide_buff_on:
			play_char.slide_buff_on = false
			transitioned.emit(self, "SlideState") 
		else:
			if play_char.move_direction: transitioned.emit(self, play_char.walk_or_run)
			else: transitioned.emit(self, "IdleState")

func input_management() -> void:
	if Input.is_action_just_pressed(play_char.jump_action):
		#check if can jump buffer
		if play_char.floor_check.is_colliding() and play_char.last_frame_position.y > play_char.position.y and play_char.nb_jumps_in_air_allowed <= 0: play_char.jump_buff_on = true
		#check if can coyote jump
		if play_char.was_on_floor and play_char.coyote_jump_cooldown > 0.0 and play_char.last_frame_position.y > play_char.position.y and play_char.jump_cooldown < 0.0:
			play_char.coyote_jump_on = true
			transitioned.emit(self, "JumpState")
		if play_char.jump_cooldown < 0.0:
			transitioned.emit(self, "JumpState")

	if Input.is_action_just_pressed(play_char.dash_action):
		if play_char.time_bef_can_dash_again <= 0.0 and play_char.nb_dashs_allowed > 0:
			transitioned.emit(self, "DashState")

	if Input.is_action_just_pressed(play_char.fly_action):
		transitioned.emit(self, "FlyState")

	if Input.is_action_just_pressed(play_char.slide_action):
		if play_char.slide_floor_check.is_colliding() and play_char.last_frame_position.y > play_char.position.y and  play_char.time_bef_can_slide_again <= 0.0:
			play_char.slide_buff_on = true

func wall_check() -> void:
	if play_char.can_wallrun and (!play_char.is_on_floor() or play_char.is_on_wall()) and !play_char.wallrun_floor_check.is_colliding():
		if play_char.left_wall_check.is_colliding() and !play_char.right_wall_check.is_colliding() and \
		play_char.last_wallrunned_wall_out_of_time != -1:
			play_char.side_check_raycast_collided = -1
			play_char.last_wallrunned_wall_out_of_time = 0
			transitioned.emit(self, "WallrunState")
		elif !play_char.left_wall_check.is_colliding() and play_char.right_wall_check.is_colliding() and \
		play_char.last_wallrunned_wall_out_of_time != 1:
			play_char.side_check_raycast_collided = 1
			play_char.last_wallrunned_wall_out_of_time = 0
			transitioned.emit(self, "WallrunState")
		else:
			return

func move(delta : float) -> void:
	play_char.input_direction = Input.get_vector(play_char.move_left_action, play_char.move_right_action, play_char.move_forward_action, play_char.move_backward_action)
	play_char.move_direction = (play_char.cam_holder.global_basis * Vector3(play_char.input_direction.x, 0.0, play_char.input_direction.y)).normalized()

	play_char.desired_move_speed = clamp(play_char.desired_move_speed, 0.0, play_char.max_desired_move_speed)

	if !play_char.is_on_floor():
		if play_char.move_direction:
			if play_char.desired_move_speed < play_char.max_desired_move_speed: play_char.desired_move_speed += play_char.bunny_hop_dms_incre * delta

			#use of curves here to have a better in air movement
			var contrd_des_move_speed : float = play_char.desired_move_speed_curve.sample(play_char.desired_move_speed)
			var contrd_in_air_move_speed : float = play_char.in_air_move_speed_curve.sample(play_char.desired_move_speed) * 1.0

			if play_char.walljump_lock_in_air_movement_time <= 0.0:
				play_char.velocity.x = lerp(play_char.velocity.x, play_char.move_direction.x * contrd_des_move_speed, contrd_in_air_move_speed * delta)
				play_char.velocity.z = lerp(play_char.velocity.z, play_char.move_direction.z * contrd_des_move_speed, contrd_in_air_move_speed * delta)

		if !play_char.move_direction and play_char.has_dashed:
			#if play char dash, and drop input direction key, need to reset velocity to her pre dash self, to ensure that play char won't keep dash velocity after transitioning to inair state
			play_char.has_dashed = false
			var velocity_tween : Tween = create_tween()
			velocity_tween.tween_method(func(v): play_char.velocity = v, play_char.velocity, Vector3(play_char.velocity_pre_dash.x, 0.0, play_char.velocity_pre_dash.z), 0.12)
			play_char.velocity_pre_dash = Vector3.ZERO
			velocity_tween.finished.connect(Callable(velocity_tween, "kill"))

class_name AIAssistantResource
extends Resource

## Name of the assistant type (e.g., "Writer", "Programmer").
@export var type_name: String

enum Mode {
	CHAT,
	AGENT,
	PLAIN
}

## The behavior mode of the assistant.
## CHAT: Standard helpful assistant without tools.
## AGENT: Autonomous agent with tool access.
## PLAIN: Direct LLM interaction without complex system instructions.
@export var mode: Mode = Mode.AGENT

## Icon displayed in hub buttons and tabs for this assistant.
@export var type_icon: Texture2D

## The name of the AI model as listed in the available models section.
@export var ai_model: String

## The class of the LLM provider resource for that model, e.g. res://addons/GodAgent/llm_providers/ollama.tres, if empty it will try to use the API selected in AI Hub tab.
@export var llm_provider: Resource

@export_group("Agent Mode Settings")
## Used to give the System message to the chat in AGENT mode.
@export_multiline var agent_description: String = '
You are an autonomous GDscript programming agent for Godot 4.5. 
Execute all possible steps to complete the orders given to you.
ALL [ext_resource] blocks MUST appear at the TOP of the file before nodes.'
## The temperature for AGENT mode.
@export_range(0.0, 1.0) var agent_temperature := 0.1
## Maximum number of autonomous steps (tool calls) the agent can perform in a row.
## Set to 0 to disable autonomous loops (manual confirmation for every step).
@export var max_autonomous_steps: int = 7
## If true, the agent will execute the whole plan automatically.
@export var auto_execute_plan: bool = true

@export_group("Chat Mode Settings")
## Used to give the System message to the chat in CHAT mode.
@export_multiline var chat_description: String = '
You are a helpful assistant.'
