class_name LLMProviderResource
extends Resource

@export var api_id: String ## Identifier of the LLM API.
@export var name: String ## User friendly name, used in the LLM Provider list.
@export var description: String ## Description to be displayed as a tooltip when hovered in the LLM Provider list.

@export_group("API key setup")
@export var requires_key: bool ## Check this if the API requires an API key to work.
@export var get_key_url: String ## If provided a link will be displayed to ease getting the API key.

@export_group("URLs setup")
@export var fix_url: String ## Used for services with a specific URL that won't change from user to user, e.g. Google Gemini. For LLMs that allow local or custom URL, keep this empty, otherwise the URL won't be editable from the UI.
@export var models_url_postfix: String ## Concatenated at the end of the server URL to produce the endpoint to get the models list. E.g. "/api/tags" for Ollama.
@export var chat_url_postfix: String ## Concatenated at the end of the server URL to produce the endpoint to chat. E.g. "/api/chat" for Ollama.

@export_group("Chat setup")
@export var system_role_name:String = "system" # Chat role name for system.
@export var user_role_name:String = "user" # Chat role name for user.
@export var assistant_role_name:String = "assistant" # Chat role name for assistant.


func _init() -> void:
	# If the provider resource doesn't have a fixed URL set, provide sensible
	# defaults per known provider so users don't need to type the server URL.
	if fix_url == "":
		match api_id:
			"openai_api":
				fix_url = "https://api.openai.com/v1"
			"openrouter_api":
				fix_url = "https://openrouter.ai/api/v1"
			"gemini_api":
				fix_url = "https://generativelanguage.googleapis.com/v1beta/models"
			"ollamaturbo_api":
				fix_url = "https://ollama.com/"
			"ollama_api":
				fix_url = "http://127.0.0.1:11434"
			"jan_api":
				fix_url = "http://127.0.0.1:3000"
			"openwebui_api":
				fix_url = "http://127.0.0.1:9000"
			_: # unknown provider: leave empty so user can configure
				pass

@tool
class_name OpenRouterAPI
extends LLMInterface

const DEPRECATED_API_KEY_SETTING := "plugins/ai_assistant_hub/openrouter_api_key"
const DEPRECATED_API_KEY_FILE := "res://addons/GodAgent/llm_apis/openrouter_api_key.gd"

var _headers: PackedStringArray # set in _initialize function


func _rebuild_headers() -> void:
	_headers = ["Content-Type: application/json",
				"Authorization: Bearer %s" % _api_key,  # Include the key in the headers
				"HTTP-Referer: godot://ai_assistant_hub", # OpenRouter requires source reference
	]


func _initialize() -> void:
	_rebuild_headers()
	llm_config_changed.connect(_rebuild_headers)


# Get model list
func send_get_models_request(http_request: HTTPRequest) -> bool:
	if not super.send_get_models_request(http_request):
		return false
	if _api_key.is_empty():
		_busy = false
		push_error("OpenRouter API key not set. Please configure the API key in the main tab and spawn a new assistant.")
		return false

	var error = http_request.request(_models_url, _headers, HTTPClient.METHOD_GET)
	if error != OK:
		_busy = false
		push_error("OpenRouter API request failed: %s" % _models_url)
		return false
	return true


# Parse model list response
func read_models_response(body: PackedByteArray) -> Array[String]:
	var json := JSON.new()
	json.parse(body.get_string_from_utf8())
	var response = json.get_data()
	if typeof(response) != TYPE_DICTIONARY:
		return [INVALID_RESPONSE]

	if response.has("data") and response.data is Array:
		var model_names: Array[String] = []
		for model in response.data:
			if model.has("id"):
				model_names.append(model.id)
		model_names.sort()
		return model_names
	else:
		push_error("Failed to get model list from OpenRouter: %s" % JSON.stringify(response))
		return [INVALID_RESPONSE]


# Send chat request
func send_chat_request(http_request: HTTPRequest, content: Array) -> bool:
	if not super.send_chat_request(http_request, content):
		return false
	if _api_key.is_empty():
		_busy = false
		push_error("OpenRouter API key not set. Please configure the API key in the main tab and spawn a new assistant.")
		return false

	if model.is_empty():
		_busy = false
		push_error("ERROR: You need to set an AI model for this assistant type.")
		return false

	# Build request body
	var body_dict := {
		"model": model,
		"messages": content
	}

	# Add temperature setting (if needed)
	if override_temperature:
		body_dict["temperature"] = temperature

	var body := JSON.stringify(body_dict)
	var error = http_request.request(_chat_url, _headers, HTTPClient.METHOD_POST, body)
	if error != OK:
		_busy = false
		push_error("OpenRouter API chat request failed.\nURL: %s\nRequest body: %s" % [_chat_url, body])
		return false
	return true


# Parse chat response
func read_response(body: PackedByteArray) -> String:
	var json := JSON.new()
	json.parse(body.get_string_from_utf8())
	var response = json.get_data()
	if typeof(response) != TYPE_DICTIONARY:
		return INVALID_RESPONSE

	if response.has("choices") and response.choices.size() > 0:
		if response.choices[0].has("message") and response.choices[0].message.has("content"):
			return ResponseCleaner.clean(response.choices[0].message.content)

	push_error("Failed to parse OpenRouter response: %s" % JSON.stringify(response))
	return INVALID_RESPONSE


# ----- Deprecated section - used to read the key to migrate to user settings file -----

static func get_deprecated_api_key() -> String:
	var old_api_key := _deprecated_load_api_key_from_file()
	if old_api_key.is_empty() and ProjectSettings.has_setting(DEPRECATED_API_KEY_SETTING):
		old_api_key = ProjectSettings.get_setting(DEPRECATED_API_KEY_SETTING)
	return old_api_key


static func _deprecated_load_api_key_from_file() -> String:
	if not FileAccess.file_exists(DEPRECATED_API_KEY_FILE):
		return ""
	var file := FileAccess.open(DEPRECATED_API_KEY_FILE, FileAccess.READ)
	if not file:
		return ""
	var content := file.get_as_text()
	file.close()
	var regex := RegEx.new()
	regex.compile('const API_KEY := "([^"]*)"')
	var result := regex.search(content)
	if result and result.get_group_count() > 0:
		return result.get_string(1)
	return ""

