		ValidationCondition.simple(
			my_max_int >= my_min_int, "my_max_int must be greater than or equal to my_min_int."
		),
		ValidationCondition.simple(
			my_min_int <= my_max_int, "my_min_int must be less than or equal to my_max_int."
		)
	]
