class_name AdaptableVectorShape3D

const STORED_CURVE_META_NAME := "_stored_curve_data_"
const STORED_ARC_LIST_META_NAME := "_stored_arc_list_data_"
const STORED_SHAPE_TYPE_META_NAME := "_stored_shape_type_"
const STORED_SIZE_META_NAME := "_stored_shape_size_"
const STORED_RX_META_NAME := "_stored_shape_rx_"
const STORED_RY_META_NAME := "_stored_shape_ry_"
const STORED_OFFSET_META_NAME := "_stored_shape_offset_"
const STORED_STROKE_WIDTH_META_NAME := "_stored_stroke_width_"
const STORED_JOINT_MODE_META_NAME := "_stored_joint_mode_"
const STORED_LINE_CAP_META_NAME := "_stored_line_cap_"

@export var guide_svs : ScalableVectorShape2D:
	set(svs):
		if is_instance_valid(guide_svs) and guide_svs != svs:
			if guide_svs.polygons_updated.is_connected(_on_guide_svs_polygons_updated):
				guide_svs.polygons_updated.disconnect(_on_guide_svs_polygons_updated)
		guide_svs = svs
		if is_instance_valid(guide_svs):
			_on_guide_svs_assigned()


@export var fill_polygons : Array[CSGPolygon3D] = []
@export var stroke_polygons : Array[CSGPolygon3D] = []

var _update_locked := false

func _on_guide_svs_assigned():
	guide_svs.update_curve_at_runtime = true
	guide_svs.polygons_updated.connect(_on_guide_svs_polygons_updated)
	guide_svs.curve_changed()


func _on_guide_svs_polygons_updated(polygons : Array[PackedVector2Array],
			poly_strokes : Array[PackedVector2Array], _svs : ScalableVectorShape2D):

	if _update_locked:
		return
	_update_locked = true
	for p in fill_polygons + stroke_polygons:
		p.hide()

	for i in polygons.size():
		if i < fill_polygons.size():
			fill_polygons[i].show()
			fill_polygons[i].polygon = polygons[i]
		else:
			var extra_fp := fill_polygons[i - 1].duplicate()
			extra_fp.polygon = polygons[i]
			fill_polygons.append(extra_fp)
			add_child(extra_fp, true)
			extra_fp.owner = owner

	for i in poly_strokes.size():
		if i < stroke_polygons.size():
			stroke_polygons[i].show()
			stroke_polygons[i].polygon = poly_strokes[i]
		else:
			var extra_sp := stroke_polygons[i - 1].duplicate()
			extra_sp.polygon = poly_strokes[i]
			stroke_polygons.append(extra_sp)
			add_child(extra_sp, true)
			extra_sp.owner = owner
	_update_locked = false

static func is_stroke_in_front_of_fill(svs : ScalableVectorShape2D) -> bool:
	var stroke_node : Node2D = (svs.line if is_instance_valid(svs.line) else svs.poly_stroke)
	if not is_instance_valid(stroke_node):
		return false
	if not is_instance_valid(svs.polygon):
		return true
	var fill_found := false
	for ch in svs.get_children():
		if ch == svs.polygon:
			fill_found = true
		if ch == stroke_node and fill_found:
			return true

	return false


static func extract_csg_polygons_from_scalable_vector_shapes(svs : ScalableVectorShape2D,
			is_strokes := false, is_line_2d_strokes := false, z_index := 0.0) -> Array[CSGPolygon3D]:
	var result : Array[CSGPolygon3D] = []
	var polygons = (
		svs.cached_poly_strokes
			if is_strokes else
		([svs.cached_outline] if svs.clip_paths.is_empty() else svs.cached_clipped_polygons)
	)
	for poly : PackedVector2Array in polygons:
		var csg_polygon := CSGPolygon3D.new()
		csg_polygon.depth = 0.01
		csg_polygon.position.z = 0.01 * z_index
		csg_polygon.polygon = poly
		csg_polygon.material = StandardMaterial3D.new()
		csg_polygon.material.shading_mode = BaseMaterial3D.SHADING_MODE_PER_PIXEL
		csg_polygon.material.transparency = BaseMaterial3D.TRANSPARENCY_DISABLED
		if is_strokes:
			csg_polygon.material.albedo_color = svs.stroke_color
			if is_line_2d_strokes:
				csg_polygon.name = svs.line.name
			else:
				csg_polygon.name = svs.poly_stroke.name
				csg_polygon.material.albedo_texture = svs.poly_stroke.texture
		else:
			csg_polygon.name = svs.polygon.name
			csg_polygon.material.albedo_color = svs.polygon.color
			csg_polygon.material.albedo_texture = svs.polygon.texture
		result.append(csg_polygon)
	return result

@tool
extends Object

class_name SVGXMLElement

const SUPPORTED_STYLES : Array[String] = ["opacity", "stroke", "stroke-width", "stroke-opacity",
		"fill", "fill-opacity", "paint-order", "stroke-linecap", "stroke-linejoin",
		"stroke-miterlimit", "clip-path"]

var name : String
var attributes : Dictionary[String, String]
var children : Array[SVGXMLElement]
var parent : SVGXMLElement

func _init(xml_parser : XMLParser, with_parent : SVGXMLElement = null):
	name = xml_parser.get_node_name()
	for i in xml_parser.get_attribute_count():
		attributes[xml_parser.get_attribute_name(i)] = xml_parser.get_attribute_value(i)
	parent = with_parent

func add_child(ch : SVGXMLElement) -> void:
	children.append(ch)


func has_attribute(x : String) -> bool:
	return x in attributes


func get_named_attribute_value(x : String) -> String:
	if x in attributes:
		return attributes[x]
	printerr("WARNING: element <%s> does not have %s" % [name, x])
	return ""


func get_node_name() -> String:
	return name


func get_named_attribute_value_safe(x : String) -> String:
	if x in attributes:
		return attributes[x]
	return ""


func find_by_id(id : String) -> SVGXMLElement:
	var ancestor = self
	while ancestor.parent != null:
		ancestor = ancestor.parent
	return find_child_by_id(id, ancestor)


func find_child_by_id(id : String, n := self) -> SVGXMLElement:
	if "id" in n.attributes and n.attributes["id"] == id:
		return n
	for nn in n.children:
		var result := find_child_by_id(id, nn)
		if result:
			return result
	return null



func is_empty() -> bool:
	return children.is_empty()


func _to_string() -> String:
	var attrs := PackedStringArray(attributes.keys().map(func(k): return k + "=\"" + attributes[k] + "\""))
	var ch := PackedStringArray(children.map(str))
	if children.is_empty():
		return "<" + name + " " + " ".join(attrs) + " />"
	else:
		return "<" + name + " " + " ".join(attrs) + ">" + "\n".join(ch) + "</" + name + ">"


func get_svg_style(log_message : Callable) -> Dictionary:
	var style = {}
	if has_attribute("style"):
		var svg_style = get_named_attribute_value("style")
		svg_style = svg_style.rstrip(";")
		svg_style = svg_style.replacen(": ", ":")
		svg_style = svg_style.replacen(":", "\":\"")
		svg_style = svg_style.replacen("; ", "\",\"")
		svg_style = svg_style.replacen(";", "\",\"")
		svg_style = "{\"" + svg_style + "\"}"
		var json = JSON.new()
		var error = json.parse(svg_style)
		if error == OK:
			style = json.data
		else:
			log_message.call("Failed to parse some styles for <%s id=\"%s\">" % [name,
					get_named_attribute_value("id") if has_attribute("id") else "?"], 2)
	for style_prop in SUPPORTED_STYLES:
		if has_attribute(style_prop):
			style[style_prop] = get_named_attribute_value(style_prop)
	return style


func get_merged_styles(log_message : Callable) -> Dictionary:
	var style = get_svg_style(log_message)
	var ancestor = self
	while ancestor.parent != null:
		style.merge(ancestor.get_svg_style(log_message))
		ancestor = ancestor.parent
	style.merge(ancestor.get_svg_style(log_message))
	return style

@tool
extends Path2D
## A custom node that extends Path2D so it can be drawn as a Line2D
## Original adapted code: https://www.hedberggames.com/blog/rendering-curves-in-godot
## @deprecated: Use [ScalableVectorShape2D] instead.
class_name  DrawablePath2D

## Emitted when a new set of points was calculated for a connected Line2D, Polygon2D, or CollisionPolygon2D
signal path_changed(new_points : PackedVector2Array)

## This signal is used internally in editor-mode to tell the DrawablePath2D tool that
## the instance of assigned Line2D, Polygon2D, or CollisionPolygon2D has changed
signal assigned_node_changed()


## The Polygon2D controlled by this Path2D
@export var polygon: Polygon2D:
	set(_poly):
		polygon = _poly
		assigned_node_changed.emit()

## The Line2D controlled by this Path2D
@export var line: Line2D:
	set(_line):
		line = _line
		assigned_node_changed.emit()

## The CollisionPolygon2D controlled by this Path2D
@export var collision_polygon: CollisionPolygon2D:
	set(_poly):
		collision_polygon = _poly
		assigned_node_changed.emit()

## Controls whether the path is treated as static (only update in editor) or dynamic (can be updated during runtime)
## If you set this to true, be alert for potential performance issues
@export var update_curve_at_runtime: bool = false

## Controls the paramaters used to divide up the line  in segments.
## These settings are prefilled with the default values.
@export_group("Tesselation settings")
## Controls how many subdivisions a curve segment may face before it is considered approximate enough.
## Each subdivision splits the segment in half, so the default 5 stages may mean up to 32 subdivisions
## per curve segment. Increase with care!
@export_range(1, 10) var max_stages : int = 5:
	set(_max_stages):
		max_stages = _max_stages
		assigned_node_changed.emit()
## Controls how many degrees the midpoint of a segment may deviate from the real curve, before the
## segment has to be subdivided.
@export_range(0.0, 180.0) var tolerance_degrees := 4.0:
	set(_tolerance_degrees):
		tolerance_degrees = _tolerance_degrees
		assigned_node_changed.emit()

var lock_assigned_shapes := true

# Wire up signals at runtime
func _ready():
	if update_curve_at_runtime:
		if not curve.changed.is_connected(curve_changed):
			curve.changed.connect(curve_changed)


# Wire up signals on enter tree for the editor
func _enter_tree():
	if Engine.is_editor_hint():
		if not curve.changed.is_connected(curve_changed):
			curve.changed.connect(curve_changed)
		if not assigned_node_changed.is_connected(_on_assigned_node_changed):
			assigned_node_changed.connect(_on_assigned_node_changed)
	# handles update when reparenting
	if update_curve_at_runtime:
		if not curve.changed.is_connected(curve_changed):
			curve.changed.connect(curve_changed)


# Clean up signals (ie. when closing scene) to prevent error messages in the editor
func _exit_tree():
	if curve.changed.is_connected(curve_changed):
		curve.changed.disconnect(curve_changed)


func _on_assigned_node_changed():
	if is_instance_valid(line):
		if lock_assigned_shapes:
			line.set_meta("_edit_lock_", true)
		curve_changed()
	if is_instance_valid(polygon):
		if lock_assigned_shapes:
			polygon.set_meta("_edit_lock_", true)
		curve_changed()
	if is_instance_valid(collision_polygon):
		if lock_assigned_shapes:
			collision_polygon.set_meta("_edit_lock_", true)
		curve_changed()


# Redraw the line based on the new curve, using its tesselate method
func curve_changed():
	if (not is_instance_valid(line) and not is_instance_valid(polygon)
			and not is_instance_valid(collision_polygon)
			and not path_changed.has_connections()):
		# guard against needlessly invoking expensive tesselate operation
		return

	var new_points := curve.tessellate(max_stages, tolerance_degrees)
	# Fixes cases start- and end-node are so close to each other that
	# polygons won't fill and closed lines won't cap nicely
	if new_points[0].distance_to(new_points[new_points.size()-1]) < 0.001:
		new_points.remove_at(new_points.size() - 1)
	if is_instance_valid(line):
		line.points = new_points
	if is_instance_valid(polygon):
		polygon.polygon = new_points
	if is_instance_valid(collision_polygon):
		collision_polygon.polygon = new_points
	path_changed.emit(new_points)


func get_bounding_rect() -> Rect2:
	var points := curve.tessellate(max_stages, tolerance_degrees)
	if points.size() < 1:
		# Cannot calculate a center for 0 points
		return Rect2(Vector2.ZERO, Vector2.ZERO)
	var minx := INF
	var miny := INF
	var maxx := -INF
	var maxy := -INF
	for p : Vector2 in points:
		minx = p.x if p.x < minx else minx
		miny = p.y if p.y < miny else miny
		maxx = p.x if p.x > maxx else maxx
		maxy = p.y if p.y > maxy else maxy
	return Rect2(minx, miny, maxx - minx, maxy - miny)


func set_position_to_center() -> void:
	var c = get_bounding_rect().get_center()
	position += c
	for i in range(curve.get_point_count()):
		curve.set_point_position(i, curve.get_point_position(i) - c)

@tool
extends Object
class_name SVSSceneExporter


static func export_image(export_root_node : Node, stored_box_ref : Dictionary[String, Vector2] = {},
		render_parent := Node.new(), forward_aa := true) -> Image:
	var sub_viewport := SubViewport.new()
	render_parent.add_child(sub_viewport)
	sub_viewport.transparent_bg = true
	sub_viewport.render_target_update_mode = SubViewport.UPDATE_ONCE
	var copied : Node = export_root_node.duplicate()
	sub_viewport.add_child(copied)
	var box = copied.get_bounding_box() if copied is ScalableVectorShape2D else [Vector2.ZERO]
	var child_list := copied.get_children()
	var min_x = box.map(func(corner): return corner.x).min()
	var min_y = box.map(func(corner): return corner.y).min()
	var max_x = box.map(func(corner): return corner.x).max()
	var max_y = box.map(func(corner): return corner.y).max()

	while child_list.size() > 0:
		var child : Node = child_list.pop_back()
		if child is Camera2D:
			child.enabled = false
		child_list.append_array(child.get_children())
		if child is ScalableVectorShape2D:
			var box1 = child.get_bounding_box()
			var min_x1 = box1.map(func(corner): return corner.x).min()
			var min_y1 = box1.map(func(corner): return corner.y).min()
			var max_x1 = box1.map(func(corner): return corner.x).max()
			var max_y1 = box1.map(func(corner): return corner.y).max()
			min_x = floori(min_x if min_x1 > min_x else min_x1)
			min_y = floori(min_y if min_y1 > min_y else min_y1)
			max_x = ceili(max_x if max_x1 < max_x else max_x1)
			max_y = ceili(max_y if max_y1 < max_y else max_y1)
	sub_viewport.canvas_transform.origin = -Vector2(min_x, min_y)
	sub_viewport.size = Vector2(max_x, max_y) - Vector2(min_x, min_y)
	if forward_aa:
		sub_viewport.msaa_2d = Viewport.MSAA_8X
	else:
		sub_viewport.screen_space_aa = Viewport.SCREEN_SPACE_AA_FXAA

	stored_box_ref["tl"] = Vector2(min_x, min_y)
	stored_box_ref["br"] = Vector2(max_x, max_y)
	await RenderingServer.frame_post_draw
	var img = sub_viewport.get_texture().get_image()
	sub_viewport.queue_free()
	return img


static func export_sprite_frames(root_node : Node,
		animation_player : AnimationPlayer,
		anim_name : String, fps : int,
		render_parent : Node, on_progress : Callable,
		forward_aa := false) -> Array[Image]:
	var interval := 1.0 / fps
	animation_player.stop()
	animation_player.current_animation = anim_name
	animation_player.get_animation(anim_name)
	var boxes : Array[Dictionary] = []
	var images : Array[Image] = []
	var frame_count := ceili(animation_player.current_animation_length / interval)
	if on_progress:
		on_progress.call("Rendering animation %s at %d fps to %d frames" % [anim_name, fps, frame_count])
	# Render each frame into an image
	for idx in range(frame_count):
		var pos = idx * interval
		if pos > animation_player.current_animation_length:
			pos = animation_player.current_animation_length
		animation_player.seek(pos, true)
		animation_player.pause()
		var box : Dictionary[String, Vector2] = {}
		var im = await export_image(root_node, box, render_parent, forward_aa)
		boxes.append(box)
		images.append(im)
	animation_player.stop()

	# Determine the bounding box into which all the rendered images would fit
	var min_x = boxes.map(func(box): return box["tl"].x).min()
	var min_y = boxes.map(func(box): return box["tl"].y).min()
	var max_x = boxes.map(func(box): return box["br"].x).max()
	var max_y = boxes.map(func(box): return box["br"].y).max()
	var return_list : Array[Image] = []

	# rerender and realign the images such that they all have the same size
	for idx in images.size():
		var im : Image = Image.create_empty(ceili(max_x) - floori(min_x), ceili(max_y) - floor(min_y), false, images[idx].get_format())
		for x in images[idx].get_size().x:
			for y in images[idx].get_size().y:
				im.set_pixel(floori(boxes[idx]["tl"].x) - min_x + x, floori(boxes[idx]["tl"].y) - min_y + y, images[idx].get_pixel(x, y))
		return_list.append(im)
	return return_list

@tool
extends Node

class_name SVGTextureHelper

# May use a class name if clutter is not a concern
# Map property names → default values
const PROPERTY_MAPPINGS: Dictionary = {
	"expand_mode": TextureRect.EXPAND_IGNORE_SIZE,
	"expand_icon": true,
	"ignore_texture_size": true
}

@export var svg_resource := SVGResource.new(): set = _set_svg_resource
@export var target_property: String = "" : set = _set_target_property

var _available_texture_properties: Array[String] = []
var _is_saving_scene: bool = false
var _cached_texture: Texture2D  # Store the actual texture to restore after save

func _ready() -> void:
	# Ensure the parent is a Control node.
	if not get_parent() is Control:
		push_error("SVGTextureHelper must be a child of a Control node.")
		queue_free()
		return

	# Detect available texture properties
	_detect_texture_properties()

	# Auto-select first available property if none is set
	if target_property.is_empty() and not _available_texture_properties.is_empty():
		target_property = _available_texture_properties[0]

	# Connect to the parent's resize signal to trigger re-renders.
	get_parent().resized.connect(_queue_render)

	# Change parent texture properties
	_update_parent_properties()

	# Connect to save signals if in editor
	if Engine.is_editor_hint():
		_connect_save_signals()

	# Perform initial render if we have a resource.
	if svg_resource:
		_queue_render()

func _connect_save_signals() -> void:
	if Engine.is_editor_hint():
		if get_tree():
			get_tree().node_configuration_warning_changed.connect(_on_scene_tree_changed)


func _on_editor_visibility_changed() -> void:
	# This is a heuristic that often correlates with save operations
	if Engine.is_editor_hint():
		_prepare_for_potential_save()

func _on_scene_tree_changed(node: Node) -> void:
	# Another heuristic for detecting editor operations that might include saving
	if Engine.is_editor_hint() and is_ancestor_of(node):
		_prepare_for_potential_save()

# Override the notification method to catch save notifications
func _notification(what: int) -> void:
	match what:
		NOTIFICATION_EDITOR_PRE_SAVE:
			_prepare_for_save()
		NOTIFICATION_EDITOR_POST_SAVE:
			_restore_after_save()
		# Also catch when the node is about to be saved
		NOTIFICATION_WM_CLOSE_REQUEST:
			if Engine.is_editor_hint():
				_prepare_for_save()

func _prepare_for_potential_save() -> void:
	# Use a timer to briefly set texture to null, then restore
	# This catches most save scenarios
	if _is_saving_scene:
		return

	_prepare_for_save()
	# Restore after a brief delay
	get_tree().create_timer(0.1).timeout.connect(_restore_after_save, CONNECT_ONE_SHOT)

func _prepare_for_save() -> void:
	if not Engine.is_editor_hint() or not get_parent() or target_property.is_empty():
		return

	if not _has_property(get_parent(), target_property):
		return

	_is_saving_scene = true

	# Store the current texture
	_cached_texture = get_parent().get(target_property) as Texture2D

	# Set texture to null to prevent it from being saved
	get_parent().set(target_property, null)

	print_rich("[color=yellow]SVGTextureHelper: Texture temporarily set to null for saving[/color]")

func _restore_after_save() -> void:
	if not Engine.is_editor_hint() or not _is_saving_scene:
		return

	_is_saving_scene = false

	# Restore the cached texture
	if get_parent() and not target_property.is_empty() and _cached_texture:
		if _has_property(get_parent(), target_property):
			get_parent().set(target_property, _cached_texture)
			print_rich("[color=green]SVGTextureHelper: Texture restored after save[/color]")

	# Clear the cache
	_cached_texture = null

func _detect_texture_properties() -> void:
	_available_texture_properties.clear()

	if not get_parent():
		return

	# Get all properties from the parent control
	var property_list = get_parent().get_property_list()

	for prop_info in property_list:
		var prop_name: String = prop_info.name
		var prop_type = prop_info.type
		var prop_class_name = prop_info.class_name

		# Check if this property accepts a Texture2D
		# This covers properties with type TYPE_OBJECT and class_name "Texture2D"
		# or properties that are explicitly documented as texture properties
		if (prop_type == TYPE_OBJECT and
			(prop_class_name == "Texture2D" or
			 prop_class_name == "Texture" or
			 prop_class_name == "ImageTexture" or
			 prop_class_name == "CompressedTexture2D")):
			_available_texture_properties.append(prop_name)
		# Also check for commonly named texture properties
		elif (prop_name.to_lower().contains("texture") or
			  prop_name.to_lower().contains("icon") or
			  prop_name in ["normal", "pressed", "hover", "disabled", "focused"]):
			# Verify it can actually accept a texture by checking if it's an Object type
			if prop_type == TYPE_OBJECT:
				_available_texture_properties.append(prop_name)

	# Sort alphabetically for better UX
	_available_texture_properties.sort()

	# Ensure we have at least some common fallbacks
	if _available_texture_properties.is_empty():
		# Add common texture property names as fallbacks
		var common_properties = ["texture", "icon", "normal", "pressed"]
		for prop in common_properties:
			if _has_property(get_parent(), prop):
				_available_texture_properties.append(prop)


func _set_target_property(new_property: String) -> void:
	if target_property == new_property:
		return

	target_property = new_property

	# Re-apply texture if we have one
	if svg_resource and svg_resource.texture and get_parent():
		_on_texture_updated(svg_resource.texture)

func _update_parent_properties() -> void:
	if get_parent() == null:
		return

	for prop in PROPERTY_MAPPINGS.keys():
		if _has_property(get_parent(), prop):
			get_parent().set(prop, PROPERTY_MAPPINGS[prop])

func _has_property(target: Object, prop_name: StringName) -> bool:
	for info in target.get_property_list():
		if info.name == prop_name:
			return true
	return false

func _set_svg_resource(new_resource: SVGResource) -> void:
	if svg_resource == new_resource:
		return

	# Disconnect from old resource if it exists
	if svg_resource:
		if svg_resource.is_connected("texture_updated", _on_texture_updated):
			svg_resource.texture_updated.disconnect(_on_texture_updated)
		# Disconnect from the changed signal
		if svg_resource.is_connected("changed", _on_resource_changed):
			svg_resource.changed.disconnect(_on_resource_changed)

	svg_resource = new_resource

	if svg_resource:
		svg_resource.texture_updated.connect(_on_texture_updated)
		# CONNECT TO THE CHANGED SIGNAL
		svg_resource.changed.connect(_on_resource_changed)

		# If the resource already has a texture, apply it immediately.
		if svg_resource.texture:
			_on_texture_updated(svg_resource.texture)

		# Queue a render to ensure it's the correct size.
		_queue_render()

# Handles resource changes
func _on_resource_changed() -> void:
	# This gets called when svg_file_path or render_scale changes
	_queue_render()

func _on_texture_updated(new_texture: Texture2D) -> void:
	if get_parent() and not target_property.is_empty():
		# Don't update texture if we're in the middle of a save operation
		if _is_saving_scene:
			_cached_texture = new_texture  # Update our cache instead
			return

		# Validate that the property exists before setting it
		if _has_property(get_parent(), target_property):
			# Set the new texture on the parent control
			get_parent().set_deferred(target_property, new_texture)
		else:
			push_warning("Property '%s' not found on parent node '%s'" % [target_property, get_parent().name])

## Called on resize or when the resource changes.
func _queue_render() -> void:
	if svg_resource == null or svg_resource.svg_string.is_empty():
		get_parent().set(target_property, null)
		return
	# Don't render during save operations
	if _is_saving_scene:
		return

	# Check for valid conditions before requesting a render.
	if not is_instance_valid(svg_resource) or not is_instance_valid(get_parent()):
		return

	if Engine.is_editor_hint() or get_tree():
		var target_size: Vector2i = get_parent().size
		var rescale_factor := 1.0
		# If parent size is invalid or zero, use a minimal 1x1 placeholder.
		# This prevents rendering a huge texture during initialization in the editor.
		# The 'resized' signal will trigger a correct render once the size is calculated.
		if target_size.x <= 0 or target_size.y <= 0:
			target_size = Vector2i(1, 1)

		var stretch_mode : TextureRect.StretchMode = get_parent().stretch_mode if "stretch_mode" in get_parent() else TextureRect.STRETCH_SCALE
		if (
			stretch_mode == TextureRect.StretchMode.STRETCH_KEEP or
			stretch_mode == TextureRect.StretchMode.STRETCH_TILE or
			stretch_mode == TextureRect.StretchMode.STRETCH_KEEP_CENTERED
		):
			rescale_factor = 1.0
		else:
			rescale_factor = (target_size.x / svg_resource.original_size.x) * svg_resource.render_scale

		var image := Image.new()
		var error := image.load_svg_from_string(Marshalls.base64_to_utf8(svg_resource.svg_string), rescale_factor)

		if error != OK:
			push_error("Failed to render SVG: " + str(error))
			return

		var image_texture := ImageTexture.create_from_image(image)
		if (
			stretch_mode == TextureRect.StretchMode.STRETCH_KEEP or
			stretch_mode == TextureRect.StretchMode.STRETCH_TILE or
			stretch_mode == TextureRect.StretchMode.STRETCH_KEEP_CENTERED
		):
			image_texture.set_size_override(svg_resource.original_size)
		else:
			get_parent().set(target_property, image_texture)


# Helper function to refresh the property list in the editor
func _refresh_properties() -> void:
	if Engine.is_editor_hint():
		_detect_texture_properties()
		notify_property_list_changed()

# Manual save preparation - you can call this from editor plugins or scripts
func manual_prepare_for_save() -> void:
	_prepare_for_save()

# Manual save restoration - you can call this from editor plugins or scripts
func manual_restore_after_save() -> void:
	_restore_after_save()

