class_name DMWBWiggleRotationModifier3D
extends SkeletonModifier3D

## Adds jiggle physics to a bone influencing the pose position.

const _SWING_LIMIT_EPSILON := 1e-4
const _DEGREES_TO_RAD := PI / 180.0

const DEFAULT := {
	handle_distance = 0.1,
}

const Functions := preload("functions.gd")

## Name of the bone to modify.
@export var bone_name := "":
	set = set_bone_name

## Properties used to move the bone.
@export var properties: DMWBWiggleRotationProperties3D:
	set = set_properties

@export_group("Force", "force")

## Applies a constant global force.
@export var force_global := Vector3.ZERO

## Applies a constant force relative to the bone's pose.
@export var force_local := Vector3.ZERO

@export_group("Editor")

## Sets the distance of the editor handle on the bone's Y axis.
@export_range(0.01, 1.0, 0.01, "or_greater", "suffix:m") var handle_distance := DEFAULT.handle_distance:
	set = set_handle_distance

var _bone_idx := -1
var _bone_parent_idx := -1
var _global_position := Vector3.ZERO # Global mass position.
var _global_direction := Vector3.UP # Global bone direction.
var _angular_velocity := Vector3.ZERO # Global angular velocity.
var _reset := true


func _enter_tree() -> void:
	_setup()


func _exit_tree() -> void:
	_bone_idx = -1
	_bone_parent_idx = -1


func _property_can_revert(property: StringName) -> bool:
	return property in DEFAULT


func _property_get_revert(property: StringName) -> Variant:
	return DEFAULT.get(property)


func _validate_property(property: Dictionary) -> void:
	match property.name:
		&"bone_name":
			var skeleton := get_skeleton()
			var bone_names := Functions.get_sorted_skeleton_bones(skeleton)

			property.hint = PROPERTY_HINT_ENUM
			property.hint_string = ",".join(bone_names)

		&"force_global", &"force_local":
			property.hint_string = &"suffix:m/s²"


func _get_configuration_warnings() -> PackedStringArray:
	var warnings := PackedStringArray()

	if not properties:
		warnings.append(tr(&"DMWBWiggleRotationProperties3D resource is required.", &"DMWB"))

	return warnings


func _process_modification() -> void:
	if _bone_idx < 0:
		return

	var skeleton := get_skeleton()
	var delta := 0.0

	match skeleton.modifier_callback_mode_process:
		Skeleton3D.MODIFIER_CALLBACK_MODE_PROCESS_IDLE:
			delta = get_process_delta_time()

		Skeleton3D.MODIFIER_CALLBACK_MODE_PROCESS_PHYSICS:
			delta = get_physics_process_delta_time()

	# Limit delta.
	delta = clampf(delta, 0.0001, 0.1)

	var skeleton_bone_parent_global_pose := skeleton.global_transform
	if _bone_parent_idx >= 0:
		skeleton_bone_parent_global_pose *= skeleton.get_bone_global_pose(_bone_parent_idx)

	var bone_pose := skeleton.get_bone_pose(_bone_idx)
	var pose_to_global := skeleton_bone_parent_global_pose * bone_pose
	var pose_to_global_rotation := pose_to_global.basis.get_rotation_quaternion()
	var global_to_pose_rotation := pose_to_global_rotation.inverse()
	var pose_global_direction := pose_to_global_rotation * Vector3.UP

	var global_position_new := pose_to_global.origin
	var global_velocity := (global_position_new - _global_position) / delta
	_global_position = global_position_new

	if _reset:
		_angular_velocity = Vector3.ZERO
		global_velocity = Vector3.ZERO

	# Global forces.
	var force := (force_global + properties.get_gravity()) * properties.force_scale
	# Add force relative to current pose.
	force += pose_to_global_rotation * force_local * properties.force_scale
	# Linear velocity.
	force -= global_velocity * properties.linear_scale

	# Add torque.
	var angular_acceleration := _global_direction.cross(force) * _DEGREES_TO_RAD
	_angular_velocity += angular_acceleration * delta

	var rotation_axis := pose_global_direction.cross(_global_direction)
	var rotation_angle := pose_global_direction.angle_to(_global_direction)
	# Use fallback axis when exactly 0° or 180°.
	if rotation_axis.is_zero_approx():
		rotation_axis = pose_to_global_rotation * Vector3.RIGHT
	rotation_axis = rotation_axis.normalized()

	# Apply rotation spring velocity without damping (see README.md).
	var frequency := properties.spring_freq * TAU
	if not is_zero_approx(frequency):
		# Rotation axis where the length is the rotation difference to the pose in radians.
		var spring_rotation := rotation_axis * rotation_angle

		var x0 := spring_rotation
		var a := delta * frequency
		var cos_ := cos(a)
		var sin_ := sin(a)
		var c2 := _angular_velocity / frequency

		spring_rotation = x0 * cos_ + c2 * sin_
		_angular_velocity = (c2 * cos_ - x0 * sin_) * frequency

		# FIXME: Handle wrapping around pole when rotation_angle > PI.
		rotation_angle = spring_rotation.length()
		if not is_zero_approx(rotation_angle):
			rotation_axis = spring_rotation / rotation_angle # Normalize axis.
			_global_direction = pose_global_direction.rotated(rotation_axis, rotation_angle)

	# No spring tension; linear rotation.
	else:
		var velocity := _angular_velocity.length()
		if not is_zero_approx(velocity):
			var velocity_axis := _angular_velocity / velocity
			var velocity_delta := velocity * delta
			_global_direction = _global_direction.rotated(velocity_axis, velocity_delta)

			# FIXME: Optimize.
			rotation_axis = pose_global_direction.cross(_global_direction)
			rotation_angle = pose_global_direction.angle_to(_global_direction)
			# Use fallback axis when exactly 0° or 180°.
			if rotation_axis.is_zero_approx():
				rotation_axis = pose_to_global_rotation * Vector3.RIGHT
			rotation_axis = rotation_axis.normalized()

	# Limit rotation and angular velocity. _SWING_LIMIT_EPSILON prevents sticking to limit.
	if rotation_angle > properties.swing_span + _SWING_LIMIT_EPSILON:
		# Limit rotation.
		_global_direction = pose_global_direction.rotated(rotation_axis, properties.swing_span)

		# Limit velocity when rotating towards limit
		if _angular_velocity.dot(rotation_axis) > 0.0:
			# Global velocity at bone tail.
			var torque_force := _angular_velocity.cross(_global_direction)
			# Limit force to tangent on swing span circle.
			torque_force = torque_force.project(rotation_axis)
			_angular_velocity = _global_direction.cross(torque_force)

	_global_direction = _global_direction.normalized()
	# Remove rotation around bone forward axis.
	_angular_velocity = Plane(_global_direction, 0.0).project(_angular_velocity)

	# Time-independent velocity damping (see README.md).
	var velocity_decay := properties.angular_damp
	_angular_velocity *= exp(-velocity_decay * delta)

	# Get rotation relative to current pose.
	var local_direction := global_to_pose_rotation * _global_direction
	var rotation_relative := Quaternion(Vector3.UP, local_direction) \
		if not is_equal_approx(local_direction.dot(Vector3.UP), -1.0) \
		else Quaternion(1.0, 0.0, 0.0, 0.0) # Rotate around X axis as fallback when rotation is exactly 180°.

	# Set bone pose rotation.
	var bone_pose_rotation := skeleton.get_bone_pose_rotation(_bone_idx)
	var bone_rotation := bone_pose_rotation * rotation_relative
	skeleton.set_bone_pose_rotation(_bone_idx, bone_rotation)

	# Apply bone transform to node.
	bone_pose.basis = Basis(bone_rotation)
	global_transform = skeleton_bone_parent_global_pose * bone_pose

	_reset = false


func set_properties(value: DMWBWiggleRotationProperties3D) -> void:
	var is_editor := Engine.is_editor_hint()

	if properties and is_editor:
		properties.changed.disconnect(_on_properties_changed)

	properties = value

	if properties and is_editor:
		properties.changed.connect(_on_properties_changed)

	_setup()
	update_gizmos()
	update_configuration_warnings()


func set_bone_name(value: String) -> void:
	bone_name = value
	_setup()
	update_gizmos()


func set_handle_distance(value: float) -> void:
	handle_distance = maxf(0.0, value)
	update_gizmos()


## Reset rotation and angular velocity.
func reset() -> void:
	_reset = true


## Add a global torque impulse.
func add_torque_impulse(torque: Vector3) -> void:
	_angular_velocity += torque


## Add a global force impulse.
func add_force_impulse(force: Vector3) -> void:
	if not properties:
		return

	force *= properties.force_scale
	var angular_acceleration := _global_direction.cross(force)
	add_torque_impulse(angular_acceleration)


func _setup() -> void:
	_bone_idx = -1

	if not properties:
		return

	var skeleton := get_skeleton()
	if not skeleton:
		return

	_bone_idx = skeleton.find_bone(bone_name)
	if _bone_idx < 0:
		return

	var skeleton_bone_pose := skeleton.get_bone_pose(_bone_idx)
	_bone_parent_idx = skeleton.get_bone_parent(_bone_idx)

	if _bone_parent_idx >= 0:
		skeleton_bone_pose = skeleton.get_bone_global_pose(_bone_parent_idx) * skeleton_bone_pose

	var global_bone_pose := skeleton.global_transform * skeleton_bone_pose
	_global_direction = (global_bone_pose.basis * Vector3.UP).normalized()
	_global_position = global_bone_pose * Vector3.UP
	_angular_velocity = Vector3.ZERO

	reset()


func _on_properties_changed() -> void:
	update_gizmos()

@tool
@icon("icons/wiggle_position_properties_3d.svg")
class_name DMWBWigglePositionProperties3D
extends Resource

## Defines the properties used to move the bone.

const DEFAULT := {
	spring_freq = 3.0,
	linear_damp = 5.0,
	force_scale = 25.0,
	linear_scale = 1.0,
	max_distance = 0.1,
	gravity = Vector3.ZERO,
}

## The spring's oscillation frequency. The frequency may change if forces are applied.
## If [code]0.0[/code], the bone is able to move freely.
## [br][br]
## [b]Note:[/b] Setting a very high value may cause the spring to become unstable.
@export_range(0.0, 10.0, 0.01, "or_greater", "suffix:Hz") var spring_freq := DEFAULT.spring_freq:
	set = set_spring_freq

## Damping factor of the velocity.
@export_range(0.0, 50.0, 0.001, "or_greater") var linear_damp := DEFAULT.linear_damp:
	set = set_linear_damp

## Defines how much the position is influenced by forces.
@export_range(0.0, 100.0, 0.001, "or_greater") var force_scale := DEFAULT.force_scale:
	set = set_force_scale

## Defines how much the position is influenced by global movement.
@export_range(0.0, 1.0, 0.001, "or_greater") var linear_scale := DEFAULT.linear_scale:
	set = set_linear_scale

## Maximum distance the bone can move around its pose position.
@export_range(0.0, 1.0, 0.001, "or_greater", "suffix:m") var max_distance := DEFAULT.max_distance:
	set = set_max_distance

## Applies a constant global force.
@export var gravity := DEFAULT.gravity:
	set = set_gravity


func _property_can_revert(property: StringName) -> bool:
	return property in DEFAULT


func _property_get_revert(property: StringName) -> Variant:
	return DEFAULT.get(property)


func _validate_property(property: Dictionary) -> void:
	match property.name:
		&"gravity":
			property.hint_string = &"suffix:m/s²"


func set_spring_freq(value: float) -> void:
	spring_freq = maxf(0.0, value)
	emit_changed()


func set_linear_damp(value: float) -> void:
	linear_damp = maxf(0.0, value)
	emit_changed()


func set_force_scale(value: float) -> void:
	force_scale = maxf(0.0, value)
	emit_changed()


func set_linear_scale(value: float) -> void:
	linear_scale = maxf(0.0, value)
	emit_changed()


func set_max_distance(value: float) -> void:
	max_distance = value
	emit_changed()


func set_gravity(value: Vector3) -> void:
	gravity = value
	emit_changed()


## Get [member gravity].
func get_gravity() -> Vector3:
	return gravity

extends EditorNode3DGizmoPlugin

const RopePathGizmoToggles = preload("rope_path_gizmo_toggles.gd")

const LINE_MAT: String = "line"
const AABB_MAT: String = "line_aabb"
const HANDLE_MAT: String = "handle"
const ORIGIN_PIN_MAT: String = "origin_sphere"
const ORIGIN_BILLBOARD_MAT: String = "origin_billboard"
const SHAPE_MATERIAL: String = "shape_material"

var lines := PackedVector3Array([])
var handles := PackedVector3Array([])

var origin_top_mesh: SphereMesh
var origin_base_mesh: CylinderMesh
var origin_billboard_mesh: PointMesh

var _plugin: RopeGenPlugin
var _toggles: RopePathGizmoToggles
var _drag_plane: Plane = Plane()
var _is_dragging: bool = false
var _selected_nodes: Array[Node] = []

func _init(plugin: RopeGenPlugin, toggles: RopePathGizmoToggles) -> void:
	_plugin = plugin
	_toggles = toggles

	# handles
	create_handle_material(HANDLE_MAT)
	create_handle_material(ORIGIN_BILLBOARD_MAT, true, preload("rope_gen_mesh_3d.svg"))
	create_material(AABB_MAT, Color('#fff380'))

	# origin
	create_material(LINE_MAT, Color('#fc7f7f'))
	create_material(ORIGIN_PIN_MAT, Color('#fc7f7f80'))
	origin_top_mesh = _create_sphere_mesh()
	origin_base_mesh = _create_cyllinder_mesh()
	origin_billboard_mesh = _create_billboard_mesh()

	# collision shapes
	var shape_color: Color = ProjectSettings.get_setting("debug/shapes/collision/shape_color")
	create_material(SHAPE_MATERIAL, shape_color)

func _get_gizmo_name() -> String:
	return "RopeGenMesh3D"

func _has_gizmo(for_node_3d) -> bool:
	return for_node_3d is RopeGenMesh3D

func _get_handle_name(gizmo: EditorNode3DGizmo, handle_id: int, secondary: bool) -> String:
	return "Rope point " + str(handle_id)

func _get_handle_value(gizmo: EditorNode3DGizmo, handle_id: int, secondary: bool) -> Variant:
	return handles[handle_id]

func _set_handle(gizmo: EditorNode3DGizmo, handle_id: int, secondary: bool, camera: Camera3D, screen_pos: Vector2) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	var pts := node.rope_data.points
	var pts_size := pts.size()

	if pts_size == 0 or handle_id >= pts_size:
		return

	if not _is_dragging:
		_drag_plane = _calc_drag_plane(node, camera, handle_id)

	var ray_from := camera.project_ray_origin(screen_pos)
	var ray_dir := camera.project_ray_normal(screen_pos)

	var intersection := _drag_plane.intersects_ray(ray_from, ray_dir)

	if intersection == null:
		return

	pts[handle_id] = node.to_local(intersection)

	# only update gizmo visuals & inspector instead of regenerating mesh while dragging
	node.notify_property_list_changed()
	_redraw(gizmo)

func _begin_handle_action(gizmo: EditorNode3DGizmo, handle_id: int, secondary: bool) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null or handle_id >= node.rope_data.points.size():
		return

	_drag_plane = _calc_drag_plane(node, EditorInterface.get_editor_viewport_3d(0).get_camera_3d(), handle_id)
	_is_dragging = true

func _commit_handle(gizmo: EditorNode3DGizmo, handle_id: int, _secondary: bool, restore: Variant, cancel: bool) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	var pts := node.rope_data.points
	var pts_size := pts.size()

	if pts_size == 0:
		return

	if cancel:
		pts[handle_id] = restore
		return

	var undo_redo: EditorUndoRedoManager = _plugin.get_undo_redo()
	var method := &"_set_rope_path_point"
	undo_redo.create_action("Set Rope Path Point")
	undo_redo.add_undo_method(self, method, node, handle_id, restore)
	undo_redo.add_do_method(self, method, node, handle_id, pts[handle_id])
	undo_redo.commit_action()

func _redraw(gizmo: EditorNode3DGizmo) -> void:
	gizmo.clear()

	var editor_selection = EditorInterface.get_selection()
	var is_selected = gizmo.get_node_3d() in editor_selection.get_selected_nodes()

	if not is_selected:
		return

	if _toggles.visible_aabbs: _draw_aabbs(gizmo)
	if _toggles.visible_collision_shapes: _draw_collision_shapes(gizmo)
	if _toggles.visible_origins: _draw_origin(gizmo)
	_draw_lines(gizmo)
	_draw_handles(gizmo)

func _draw_lines(gizmo: EditorNode3DGizmo) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	var pts := node.rope_data.points
	var pts_size := pts.size()

	if pts_size < 2: 
		return

	lines.clear()

	for i in range(pts_size - 1):
		lines.push_back(pts[i])
		lines.push_back(pts[i + 1])

	gizmo.add_lines(lines, get_material(LINE_MAT, gizmo))

func _draw_handles(gizmo: EditorNode3DGizmo) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	var pts := node.rope_data.points
	var pts_size := pts.size()

	if pts_size == 0:
		return

	handles.clear()

	for i in range(pts_size):
		handles.push_back(pts[i])

	gizmo.add_handles(handles, get_material(HANDLE_MAT, gizmo), [])

func _draw_aabbs(gizmo: EditorNode3DGizmo) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	for mesh in node.vis_instance_meshes:
		lines.clear()
		lines = _get_aabb_lines(mesh.get_aabb())
		gizmo.add_lines(lines, get_material(AABB_MAT, gizmo))

func _draw_collision_shapes(gizmo: EditorNode3DGizmo) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	if node.rope_data == null: 
		return

	if not node.rope_data.use_collisions or node.rope_data.points.size() == 0:
		return

	var xform_base := Transform3D()
	var st := SurfaceTool.new()

	for shape in node.phys_instance_shapes:
		st.append_from(shape.get_debug_mesh(), 0, xform_base)

	gizmo.add_mesh(st.commit(), get_material(SHAPE_MATERIAL, gizmo))


func _draw_origin(gizmo: EditorNode3DGizmo) -> void:
	var node := gizmo.get_node_3d() as RopeGenMesh3D

	var xform_base := Transform3D()
	xform_base.origin = Vector3(0.0, 0.25, 0.0)

	var xform_top := Transform3D()
	xform_top.origin = Vector3(0.0, 0.6, 0.0)

	var xform_billboard := Transform3D()
	xform_billboard.origin = Vector3(0.0, 0.85, 0.0)

	gizmo.add_mesh(origin_base_mesh, get_material(ORIGIN_PIN_MAT, gizmo), xform_base)
	gizmo.add_mesh(origin_top_mesh, get_material(ORIGIN_PIN_MAT, gizmo), xform_top)
	gizmo.add_mesh(origin_billboard_mesh, get_material(ORIGIN_BILLBOARD_MAT, gizmo), xform_billboard)

func _set_rope_path_point(rope_gen: RopeGenMesh3D, id: int, pos: Vector3) -> void:
	if rope_gen && rope_gen.rope_data && rope_gen.rope_data.points.size() > 0:
		var pts := rope_gen.rope_data.points
		pts[id] = pos
		rope_gen.rope_data.emit_changed()

func _calc_drag_plane(rope_gen: RopeGenMesh3D, camera_3d: Camera3D, handle_id: int) -> Plane:
	var current_point_local := rope_gen.rope_data.points[handle_id]
	var current_point_global := rope_gen.to_global(current_point_local)
	var camera_normal := -camera_3d.global_transform.basis.z

	return Plane(camera_normal, current_point_global.dot(camera_normal))

func _get_aabb_lines(aabb: AABB) -> PackedVector3Array:
	var c: Array[Vector3] = [
		aabb.position,
		aabb.position + Vector3(aabb.size.x, 0, 0),
		aabb.position + Vector3(aabb.size.x, aabb.size.y, 0),
		aabb.position + Vector3(0, aabb.size.y, 0),
		aabb.position + Vector3(0, 0, aabb.size.z),
		aabb.position + Vector3(aabb.size.x, 0, aabb.size.z),
		aabb.end,
		aabb.position + Vector3(0, aabb.size.y, aabb.size.z)
	]

	return PackedVector3Array([
		c[0], c[1], c[1], c[2], c[2], c[3], c[3], c[0],  # bottom
		c[4], c[5], c[5], c[6], c[6], c[7], c[7], c[4],  # top
		c[0], c[4], c[1], c[5], c[2], c[6], c[3], c[7]   # verticals
	])

func _create_sphere_mesh() -> SphereMesh:
	var sph := SphereMesh.new()
	sph.radius = 0.125
	sph.height = 0.25
	sph.radial_segments = 8
	sph.rings = 4

	return sph

func _create_cyllinder_mesh() -> CylinderMesh:
	var cyl := CylinderMesh.new()
	cyl.top_radius = 0.03
	cyl.bottom_radius = 0.03
	cyl.height = 0.5
	cyl.radial_segments = 8
	cyl.rings = 0
	cyl.cap_top = false

	return cyl

func _create_billboard_mesh() -> PointMesh:
	return PointMesh.new()

@tool
class_name RopeGenMesh3D extends Node3D

enum RopeDisableMode {
	REMOVE = 0, ## StaticBody is removed from the physics world space when node [member process_mode] is set to disabled.
	KEEP_STATIC = 1 ## StaticBody is being kept in the physics world space when [member process_mode] is set to disabled.
}

## Emitted when mesh generation finishes.
signal generation_finished()

# visuals
var current_vis_instance_idx := 0
var vis_instance_rids: Array[RID]
var vis_instance_meshes: Array[ArrayMesh]
var scenario: RID

# physics
var current_phys_instance_idx := 0
var phys_instance_rids: Array[RID]
var phys_instance_shapes: Array[Shape3D]

@export_tool_button("Regenerate meshes") var manual_regen: Callable

@export var rope_data: RopeData:
	set = _set_rope_data

## Specifies how the collisions (if enabled) of the rope should behave when node's [member process_mode] changes during game runtime.
@export var disable_mode: RopeDisableMode = RopeDisableMode.REMOVE

func _enter_tree() -> void:
	scenario = get_world_3d().scenario

	# gameplay
	if not Engine.is_editor_hint():
		if not has_generated_mesh():
			_regen_meshes(rope_data)
		return

	# editor
	if rope_data != null:
		if not rope_data.changed.is_connected(_on_rope_data_changed):
			rope_data.changed.connect(_on_rope_data_changed)
		if not has_generated_mesh():
			_regen_meshes(rope_data)

func _exit_tree() -> void:
	_free_rs_instances()
	_free_ps_instances()

	# gameplay
	if not Engine.is_editor_hint():
		return

	# editor
	if rope_data != null and rope_data.changed.is_connected(_on_rope_data_changed):
		rope_data.changed.disconnect(_on_rope_data_changed)

func _notification(what: int) -> void:
	match what:
		NOTIFICATION_DISABLED:
			_disable_physics_space()
		NOTIFICATION_ENABLED:
			_enable_physics_space()

	if not has_generated_mesh() or not Engine.is_editor_hint():
		return

	match what:
		NOTIFICATION_TRANSFORM_CHANGED:
			# _update_rs_instance_xforms(rope_data)
			_regen_meshes(rope_data)
		NOTIFICATION_VISIBILITY_CHANGED:
			_update_rs_instance_visibility(rope_data)

func _regen_meshes(data: RopeData) -> void:
	_free_rs_instances()
	_free_ps_instances()

	if data == null or data.points.size() < 2:
		return

	var points := data.points
	var points_size := points.size()

	if data.single_mesh:
		# origin point of a signle mesh is located at segment_points[0]

		#region Single mesh generation
		var segment_points := PackedVector3Array()
		var segment_normals := PackedVector3Array()
		var segment_t_values := PackedFloat32Array()

		for i in range(points_size - 1):
			var start_point := points[i]
			var end_point := points[i + 1]
			var dir := start_point.direction_to(end_point)
			var dist := start_point.distance_to(end_point)

			var rings := rope_data.ext_v_segments
			for j in range(rings):
				var t := float(j) / (rings - 1)
				segment_points.push_back(start_point + dir * dist * t)
				segment_t_values.push_back(t)

		segment_normals = _calculate_tangents(segment_points)
		var array_mesh := _extrude_along_points_path(global_basis, rope_data, segment_points, segment_normals, segment_t_values, points_size)

		_create_rs_instance(rope_data, array_mesh, global_transform)

		if data.use_collisions:
			var shape := _generate_shape(array_mesh, data.col_shape_type)
			_create_ps_instance(data, shape, global_transform)

		#endregion
	else:
		# origin points of multiple meshes are located at segment_points respectively
		#region Multiple meshes generation
		for i in range(points_size - 1):
			var segment_points := PackedVector3Array()
			var segment_normals := PackedVector3Array()
			var segment_t_values := PackedFloat32Array()

			var start_point := points[i]
			var end_point := points[i + 1]
			var dir := start_point.direction_to(end_point)
			var dist := start_point.distance_to(end_point)

			var rings := rope_data.ext_v_segments
			for j in range(rings):
				var t := float(j) / (rings - 1) 
				segment_points.push_back(start_point + dir * dist * t)
				segment_t_values.push_back(t)

			segment_normals = _calculate_tangents(segment_points)
			var array_mesh = _extrude_along_points_path(global_basis, rope_data, segment_points, segment_normals, segment_t_values, points_size, i)

			_create_rs_instance(rope_data, array_mesh, global_transform)

			if data.use_collisions:
				var shape := _generate_shape(array_mesh, data.col_shape_type)
				_create_ps_instance(data, shape, global_transform)
		#endregion

	generation_finished.emit()


#region Mesh generation internals
func _calculate_tangents(points: PackedVector3Array) -> PackedVector3Array:
	assert(points.size() >= 2, "Cannot calculate tangent normals for points array of size less than 2")

	var tangents := PackedVector3Array()
	var count := points.size()

	for i in range(count):
		var tangent: Vector3
		if i == 0:
			#tangent = (points[1] - points[0]).normalized()
			tangent = points[0].direction_to(points[1])
		elif i == count - 1:
			#tangent = (points[i] - points[i - 1]).normalized()
			tangent = points[i - 1].direction_to(points[i])
		else:
			#tangent = (points[i + 1] - points[i - 1]).normalized()
			tangent = points[i - 1].direction_to(points[i + 1])

		tangents.push_back(tangent)

	return tangents

func _calculate_cumulative_distances(points: PackedVector3Array) -> PackedFloat32Array:
	var distances := PackedFloat32Array()
	var cumulative := 0.0
	var count := points.size()

	distances.push_back(0.0)

	for i in range(1, count):
		var segment_length := points[i].distance_to(points[i - 1])
		cumulative += segment_length
		distances.push_back(cumulative)

	return distances

func _generate_lod_indices(ring_count: int, p_segments: int, ring_step: int, segment_step: int) -> PackedInt32Array:
	var indices := PackedInt32Array()
	var verts_per_ring := p_segments + 1

	var ring_idx := 0
	while ring_idx < ring_count - 1:
		var next_ring_idx := mini(ring_idx + ring_step, ring_count - 1)

		var seg_idx := 0
		while seg_idx < p_segments:
			var next_seg_idx := mini(seg_idx + segment_step, p_segments)

			var curr_start := ring_idx * verts_per_ring
			var next_start := next_ring_idx * verts_per_ring

			var bl = curr_start + seg_idx
			var br = curr_start + next_seg_idx
			var tl = next_start + seg_idx
			var tr = next_start + next_seg_idx

			indices.append_array([
				bl, br, tl, 
				br, tr, tl
			])

			seg_idx += segment_step

		ring_idx += ring_step

	return indices

func _extrude_along_points_path(
	p_node_basis: Basis,
	p_rope_data: RopeData,
	p_points: PackedVector3Array, 
	p_normals: PackedVector3Array,
	p_t_values: PackedFloat32Array,
	p_hooks_count: int,
	p_segment_index: int = -1,
) -> ArrayMesh:
	#region ====== 0. Data gathering & assertions ======
	assert(p_points.size() == p_normals.size(), "Points and normals array must have the same size")
	assert(p_points.size() == p_t_values.size(), "Points and t_values array must have the same size")
	assert(p_points.size() >= 2, "At least 2 points are needed")

	var p_sag_offset := rope_data.sag_offset
	var p_sag_keep_local := rope_data.sag_keep_local_space
	var p_radius := rope_data.ext_radius
	var p_u_segments := rope_data.ext_u_segments
	var p_v_segments := rope_data.ext_v_segments
	var p_material := rope_data.material
	var p_uv_translate := rope_data.tex_uv_translation
	var p_uv_scale := rope_data.tex_uv_scale
	var p_uv_rot_origin := rope_data.tex_uv_rotation_origin
	var p_uv_rot_angle_deg := rope_data.tex_uv_rotation_angle_degrees
	var p_lod1_dist := rope_data.lod_level1_distance
	var p_lod2_dist := rope_data.lod_level2_distance
	var p_lod3_dist := rope_data.lod_level3_distance
	#endregion

	#region ====== 1. Ring frames matrices construction ======
	var frames: Array[Basis] = []

	var forward := p_normals[0].normalized()
	var up := Vector3.UP

	if abs(forward.dot(up)) > 0.99:
		up = Vector3.FORWARD

	var right = forward.cross(up).normalized()
	up = right.cross(forward).normalized()

	frames.push_back(Basis(right, up, forward))

	var ring_count := p_points.size()
	for i in range(1, ring_count):
		var prev_forwad := p_normals[i - 1].normalized()
		var curr_forward := p_normals[i].normalized()

		var prev_right := frames[i - 1].x
		var prev_up := frames[i - 1].y

		var rot_axis := prev_forwad.cross(curr_forward)

		if rot_axis.length_squared() > 0.0001:
			rot_axis = rot_axis.normalized()
			var rot_angle := prev_forwad.angle_to(curr_forward)
			var rot := Basis(rot_axis, rot_angle)

			var new_right := (rot * prev_right).normalized()
			var new_up := (rot * prev_up).normalized()

			frames.push_back(Basis(new_right, new_up, curr_forward))
		else:
			frames.push_back(Basis(prev_right, prev_up, curr_forward))
	#endregion

	#region ====== 2. Vertex data construction ======
	var vertices_arr := PackedVector3Array()
	var normals_arr := PackedVector3Array()
	var uvs_arr := PackedVector2Array()
	var colors_arr := PackedColorArray()
	var distances := _calculate_cumulative_distances(p_points)

	var uv_angle := deg_to_rad(p_uv_rot_angle_deg)
	var cos_uv_rot := cos(uv_angle)
	var sin_uv_rot := sin(uv_angle)
	var current_hook := 0.0

	for ring_idx in range(ring_count):
		var center := p_points[ring_idx]
		var frame := frames[ring_idx]
		var frame_right := frame.x
		var frame_up := frame.y

		var v := (p_t_values[ring_idx] * float(p_v_segments - 1))
		var t := p_t_values[ring_idx]

		var anim_offset: float

		if p_segment_index == -1:
			# no index passed, single mesh - infer the animation offset from t_values
			current_hook += floorf(p_t_values[maxi(ring_idx - 1, 0)])
			anim_offset = current_hook / float(p_hooks_count)
		else:
			anim_offset = (current_hook + float(p_segment_index)) / float(p_hooks_count)

		var sag_factor := sin(t * PI)

		# vertex colors:
		# red = how far from the hook is current vertex, or - how much affected by the wind forces the rope is at this place
		# green = segment/mesh based offset, to break unison movement
		var ring_color := Color(sag_factor, anim_offset, 0.0, 0.0)

		var verts_per_ring := p_u_segments + 1
		for i in range(verts_per_ring):
			var angle := float(i) / p_u_segments * TAU
			var cos_a := cos(angle)
			var sin_a := sin(angle)

			var offset := (frame_right * cos_a + frame_up * sin_a) * p_radius
			var sag_offset := p_sag_offset * sag_factor if p_sag_keep_local else p_node_basis.inverse() * p_sag_offset * sag_factor
			var vertex_pos := center + offset + sag_offset
			var vertex_normal = offset.normalized()
			var u = (float(i) / p_u_segments)

			var uv := Vector2(u, v)

			# first - scale and translate UV in local space
			var xformed_uv = (
				Transform2D()
					.scaled(p_uv_scale)
					.translated(p_uv_translate)
			) * uv

			# then - rotate around the specified global space origin point
			# avoids non-uniform scale skewing issues arising when doing this in one step
			xformed_uv = (
				Transform2D()
					.translated(-p_uv_rot_origin)
					.rotated(uv_angle)
					.translated(p_uv_rot_origin)
			) * xformed_uv

			vertices_arr.push_back(vertex_pos)
			normals_arr.push_back(vertex_normal)
			uvs_arr.push_back(xformed_uv)
			colors_arr.push_back(ring_color)
	#endregion

	#region ====== 3. ImporterMesh creation ======
	var importer_mesh := ImporterMesh.new()
	var indices_lod0 := _generate_lod_indices(ring_count, p_u_segments, 1, 1)

	var base_arrays = []
	base_arrays.resize(Mesh.ARRAY_MAX)
	base_arrays[Mesh.ARRAY_VERTEX] = vertices_arr
	base_arrays[Mesh.ARRAY_NORMAL] = normals_arr
	base_arrays[Mesh.ARRAY_TEX_UV] = uvs_arr;
	base_arrays[Mesh.ARRAY_COLOR] = colors_arr;
	base_arrays[Mesh.ARRAY_INDEX] = indices_lod0

	var indices_lod1 := _generate_lod_indices(ring_count, p_u_segments, 2, 2)
	var indices_lod2 := _generate_lod_indices(ring_count, p_u_segments, 4, 4)
	var indices_lod3 := _generate_lod_indices(ring_count, p_u_segments, 8, 8)

	var lods := {}
	lods[p_lod1_dist] = indices_lod1
	lods[p_lod2_dist] = indices_lod2
	lods[p_lod3_dist] = indices_lod3

	importer_mesh.add_surface(
		Mesh.PRIMITIVE_TRIANGLES, 
		base_arrays, 
		[], 
		lods, 
		p_material, 
		"RopeSurface", 
		Mesh.ARRAY_FLAG_COMPRESS_ATTRIBUTES
	)

	#endregion

	var array_mesh := importer_mesh.get_mesh()

	return array_mesh

#endregion

#region RenderingServer instance methods
func _create_rs_instance(rope_data: RopeData, mesh: ArrayMesh, xform: Transform3D) -> void:
	var rs := RenderingServer
	var instance_rid = rs.instance_create()

	rs.instance_set_base(instance_rid, mesh.get_rid())
	rs.instance_set_scenario(instance_rid, scenario)
	rs.instance_set_transform(instance_rid, xform)
	rs.instance_set_visible(instance_rid, visible)
	rs.instance_set_layer_mask(instance_rid, rope_data.visibility_layers)
	rs.instance_geometry_set_lod_bias(instance_rid, rope_data.lod_bias)
	rs.instance_geometry_set_cast_shadows_setting(instance_rid, rs.SHADOW_CASTING_SETTING_ON)

	rs.instance_teleport(instance_rid)

	vis_instance_rids.push_back(instance_rid)
	vis_instance_meshes.push_back(mesh)
	current_vis_instance_idx += 1

func _update_rs_instance_xforms(rope_data: RopeData) -> void:
	var rs := RenderingServer
	var i := 0

	while i < current_vis_instance_idx:
		var rid := vis_instance_rids[i]
		rs.instance_set_transform(rid, global_transform)
		i += 1

func _update_rs_instance_visibility(rope_data: RopeData) -> void:
	var rs := RenderingServer
	var i := 0

	while i < current_vis_instance_idx:
		var rid := vis_instance_rids[i]
		rs.instance_set_visible(rid, visible)
		i += 1

func _free_rs_instances() -> void:
	for rid in vis_instance_rids:
		RenderingServer.free_rid(rid)

	vis_instance_rids.clear()
	vis_instance_meshes.clear()
	current_vis_instance_idx = 0
#endregion

#region PhysicsServer instance methods
func _generate_shape(mesh: ArrayMesh, type: RopeData.ColShapeType) -> Shape3D:
	match type:
		RopeData.ColShapeType.TRIMESH:
			return mesh.create_trimesh_shape()
		RopeData.ColShapeType.SINGLE_CONVEX:
			return mesh.create_convex_shape(true, false)
		RopeData.ColShapeType.SIMPLIFIED_CONVEX:
			return mesh.create_convex_shape(true, true)
		_:
			return mesh.create_trimesh_shape()

func _disable_physics_space() -> void:
	var ps := PhysicsServer3D

	for body_rid in phys_instance_rids:
		if disable_mode == RopeDisableMode.REMOVE:
			if is_inside_tree(): ps.body_set_space(body_rid, RID())

func _enable_physics_space() -> void:
	var ps := PhysicsServer3D

	for body_rid in phys_instance_rids:
		if disable_mode == RopeDisableMode.REMOVE:
			if is_inside_tree(): ps.body_set_space(body_rid, get_world_3d().space)

func _create_ps_instance(rope_data: RopeData, shape: Shape3D, xform: Transform3D) -> void:
	var ps := PhysicsServer3D
	var body_rid := ps.body_create()

	ps.body_set_mode(body_rid, PhysicsServer3D.BODY_MODE_STATIC)
	ps.body_set_space(body_rid, get_world_3d().space)
	ps.body_add_shape(body_rid, shape.get_rid())
	ps.body_set_collision_layer(body_rid, rope_data.col_collision_layer)
	ps.body_set_collision_mask(body_rid, rope_data.col_collision_mask)
	ps.body_set_state(body_rid, PhysicsServer3D.BODY_STATE_TRANSFORM, xform)

	phys_instance_rids.push_back(body_rid)
	phys_instance_shapes.push_back(shape)
	current_phys_instance_idx += 1

func _free_ps_instances() -> void:
	for rid in phys_instance_rids:
		PhysicsServer3D.free_rid(rid)

	phys_instance_rids.clear()
	phys_instance_shapes.clear()
	current_phys_instance_idx = 0
#endregion

func _set_rope_data(value) -> void:
	if Engine.is_editor_hint() \
	and rope_data != null \
	and rope_data.changed.is_connected(_on_rope_data_changed):
		rope_data.changed.disconnect(_on_rope_data_changed)

	rope_data = value

	if Engine.is_editor_hint():
		manual_regen = func(): _regen_meshes(rope_data) if rope_data else null

		if rope_data != null:
			if not rope_data.changed.is_connected(_on_rope_data_changed):
				rope_data.changed.connect(_on_rope_data_changed)
			if is_inside_tree():
				_regen_meshes(rope_data)
		else:
			_free_rs_instances()

func _on_rope_data_changed() -> void:
	if Engine.is_editor_hint():
		update_gizmos()
	if rope_data != null and is_inside_tree():
		_regen_meshes(rope_data)

# public api
func has_generated_mesh() -> bool:
	return rope_data != null and not vis_instance_rids.is_empty()

## Calculates 3d point in global coordinates which will be placed at given index point of [member rope_data], 
## interpolated by the [member factor] to the next index, point will be affected by sag factor.
## Use it when you want to spawn things "on" the rope.
func calculate_global_point_at(rope_point_idx: int, factor: float) -> Vector3:
	if rope_data == null or rope_data.points.is_empty():
		return Vector3.ZERO

	var points := rope_data.points
	var points_size := points.size()

	rope_point_idx = clampi(rope_point_idx, 0, points_size - 1)
	factor = clampf(factor, 0.0, 1.0)

	# if at the last point or factor is 0, return the point at index
	if rope_point_idx >= points_size - 1 or factor == 0.0:
		var point := points[rope_point_idx]
		var sag_factor := 0.0 if rope_point_idx == 0 or rope_point_idx == points_size - 1 else 1.0
		var sag_offset := rope_data.sag_offset * sag_factor if rope_data.sag_keep_local_space else global_basis.inverse() * rope_data.sag_offset * sag_factor
		return global_transform * (point + sag_offset)

	var start_point := points[rope_point_idx]
	var end_point := points[rope_point_idx + 1]
	var interpolated_point := start_point.lerp(end_point, factor)

	var t := (float(rope_point_idx) + factor) / float(points_size - 1)
	var sag_factor := sin(t * PI)

	var sag_offset := rope_data.sag_offset * sag_factor if rope_data.sag_keep_local_space else global_basis.inverse() * rope_data.sag_offset * sag_factor

	return global_transform * (interpolated_point + sag_offset)

@tool
class_name RopeGenPlugin extends EditorPlugin

const RopePathGizmo = preload("rope_path_gizmo.gd")
const RopePathGizmoToggles = preload("rope_path_gizmo_toggles.gd")
const RopeGenGui = preload("gui/rope_gen_gui_mesh_toolbar_button.gd")

var rope_path_gizmo_plugin: RopePathGizmo
var rope_gen_gui: RopeGenGui

func _enter_tree() -> void:
	var icon = preload("rope_gen_mesh_3d.svg")
	var gizmo_toggles := RopePathGizmoToggles.new()

	rope_path_gizmo_plugin = RopePathGizmo.new(self, gizmo_toggles)
	add_node_3d_gizmo_plugin(rope_path_gizmo_plugin)
	add_custom_type("RopeGenMesh3D", "Node3D", preload("rope_gen_mesh_3d.gd"), icon)

	var editor_selection = get_editor_interface().get_selection()
	editor_selection.selection_changed.connect(_on_selection_changed)

	rope_gen_gui = RopeGenGui.new(self)\
		.add_gizmo_toggles(gizmo_toggles)

func _exit_tree() -> void:
	rope_gen_gui.cleanup()
	remove_node_3d_gizmo_plugin(rope_path_gizmo_plugin)
	remove_custom_type("RopeGenMesh3D")

func _on_selection_changed() -> void:
	var selected = get_editor_interface().get_selection().get_selected_nodes()
	_refresh_gizmos(selected)

func _refresh_gizmos(nodes: Array[Node]) -> void:
	if nodes.is_empty():
		get_tree().root.propagate_call(&"update_gizmos")
		return

	for node in nodes:
		if not is_instance_valid(node):
			continue

		if node is RopeGenMesh3D:
			node.update_gizmos()

@tool
extends RefCounted

const RopePathGizmoToggles = preload("../rope_path_gizmo_toggles.gd")

enum GizmoCheckbox {
	SHOW_AABBS = 10,
	SHOW_COLLISION_SHAPES = 11, 
	SHOW_ORIGIN = 12,
}

var _plugin: EditorPlugin
var _submenu: PopupMenu
var _toggles: RopePathGizmoToggles
var _submenu_name := "DebugGizmos"

func _init(plugin: EditorPlugin) -> void:
	_plugin = plugin
	_create_submenu()

func _create_submenu() -> void:
	_submenu = PopupMenu.new()
	_submenu.name = _submenu_name
	_submenu.add_check_item("Show AABBs", GizmoCheckbox.SHOW_AABBS)
	_submenu.add_check_item("Show CollisionShapes", GizmoCheckbox.SHOW_COLLISION_SHAPES)
	_submenu.add_check_item("Show Origins", GizmoCheckbox.SHOW_ORIGIN)
	_submenu.id_pressed.connect(_on_gizmos_submenu_item_pressed)

func _on_gizmos_submenu_item_pressed(id: int) -> void:
	match id:
		GizmoCheckbox.SHOW_AABBS:
			_toggles.visible_aabbs = not _toggles.visible_aabbs
		GizmoCheckbox.SHOW_COLLISION_SHAPES:
			_toggles.visible_collision_shapes = not _toggles.visible_collision_shapes
		GizmoCheckbox.SHOW_ORIGIN:
			_toggles.visible_origins = not _toggles.visible_origins

	_reflect_toggles_in_submenu()
	_plugin.get_tree().root.propagate_call(&"update_gizmos")

func _reflect_toggles_in_submenu() -> void:
	if _toggles == null:
		return

	var show_aabbs_idx := _submenu.get_item_index(GizmoCheckbox.SHOW_AABBS)
	var show_collsion_shapes_idx := _submenu.get_item_index(GizmoCheckbox.SHOW_COLLISION_SHAPES)
	var show_origin_idx := _submenu.get_item_index(GizmoCheckbox.SHOW_ORIGIN)

	_submenu.set_item_checked(show_aabbs_idx, _toggles.visible_aabbs)
	_submenu.set_item_checked(show_collsion_shapes_idx, _toggles.visible_collision_shapes)
	_submenu.set_item_checked(show_origin_idx, _toggles.visible_origins)

# public interface
func set_toggles(toggles: RopePathGizmoToggles) -> void:
	_toggles = toggles
	_reflect_toggles_in_submenu.call_deferred()

func get_submenu() -> PopupMenu:
	return _submenu

func get_submenu_name() -> String:
	return _submenu.name

func cleanup() -> void:
	_submenu.queue_free()

